import type { Drill } from "./types";

// Construction / early drills, keyed by module slug — 25 per module.
// Apprentice or tradesperson (electrician, plumber, carpenter, equipment
// operator) on site or on service calls: clear questions to the foreman,
// safety flags, homeowner explanations, trade coordination. Merged into course.ts.
export const CONSTRUCTION_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-constr-early-01","level":"early","profession":"construction","title":"The wire shortage text","scenario":"You're roughing in the second floor and just realized you'll run out of 12/2 wire before lunch. Your text to the foreman starts with a recap of everything you've pulled so far this morning.","task":"Write a text that puts the shortage and what you need in the first sentence.","tips":["First words: what you're short on and how much you need.","How far you've gotten is support — it can come after.","Say when you'll be stopped so he can judge the urgency."],"focus":["clarity","impact"],"placeholder":"Short on 12/2 — need two more rolls by 11 or I'm stopped upstairs."},
    {"id":"lead-constr-early-02","level":"early","profession":"construction","title":"Blocked behind the plumber","scenario":"You can't close up the bathroom wall until the plumber finishes his pressure test, and he's not on site today. Your message to the foreman rambles about your morning before you get to the fact that you're stuck.","task":"Write a 1-2 sentence message that leads with the blocker and asks what to work on instead.","tips":["Lead with what's stopping you and who you're waiting on.","Ask a specific question: where do you want me instead?","Don't bury the point under a diary of your day."],"focus":["clarity","structure"]},
    {"id":"lead-constr-early-03","level":"early","profession":"construction","title":"You dinged the drywall","scenario":"Carrying a ladder through the finished hallway, you gouged the fresh drywall by the stairs. Nobody saw it. You want to tell the foreman, but your draft opens with three sentences about how tight the hallway is.","task":"Write a message that states the damage in the first sentence, then how you'll fix it.","tips":["Say what happened first: gouged drywall, hallway by the stairs.","Excuses before the point read like hiding.","Follow with the fix: mud it yourself or flag the taper?"],"focus":["clarity","impact"],"placeholder":"I gouged the hall drywall by the stairs carrying a ladder —"},
    {"id":"lead-constr-early-04","level":"early","profession":"construction","title":"The failed-inspection voicemail","scenario":"The rough-in inspection failed on two items: a missing nail plate and an unsecured cable in the joist bay. You need to leave the office a voicemail, and you tend to start with the whole story of the inspector's visit.","task":"Say a voicemail (or write it out) that leads with the result: failed, two items, both fixable today.","tips":["First sentence: failed, how many items, how bad.","The two items come next, one breath each.","End with the plan: fixed today, re-inspection to book."],"focus":["structure","concision"],"placeholder":"Rough-in failed on two small items — both fixed by end of day."},
    {"id":"lead-constr-early-05","level":"early","profession":"construction","title":"Your turn at the morning huddle","scenario":"At the 7 a.m. huddle the foreman points at you. You're tempted to walk through everything you did yesterday. What actually matters: kitchen circuits are done, and you need the panel schedule before you can label.","task":"Give a 2-sentence huddle update that leads with where you are and what you need.","tips":["Status first: kitchen circuits done.","Then the one thing you need to keep moving.","Yesterday's play-by-play is noise at 7 a.m."],"focus":["concision","clarity"]},
    {"id":"lead-constr-early-06","level":"early","profession":"construction","title":"When will you be done?","scenario":"The homeowner catches you at the truck and asks when the bathroom will be usable again. You know it's Thursday if the fixtures arrive tomorrow. Your instinct is to explain the supply-house situation first.","task":"Answer in 1-2 sentences that lead with the date.","tips":["Give the date in the first breath: Thursday.","The condition comes second, short: if fixtures land tomorrow.","Homeowners remember the first thing you say — make it the answer."],"focus":["clarity","precision"],"placeholder":"Thursday, as long as your fixtures show up tomorrow like they're supposed to."},
    {"id":"lead-constr-early-07","level":"early","profession":"construction","title":"The buried question","scenario":"You need to know from the foreman whether the laundry gets a dedicated 20-amp circuit or shares with the bathroom. Your text tells the whole story of the panel layout before the question shows up in line six.","task":"Rewrite the text so the question is the first sentence.","tips":["Ask first: dedicated circuit for laundry, or shared?","Add only the context he needs to answer.","A question he can answer from his truck gets answered fast."],"focus":["clarity","concision"],"placeholder":"Quick one: does the laundry get its own 20A circuit or share with the bath?"},
    {"id":"lead-constr-early-08","level":"early","profession":"construction","title":"Hole in the floor","scenario":"Walking materials in, you spot an uncovered floor opening on the second storey where the HVAC crew pulled a duct chase. Anyone stepping back off the ladder could go through it. You grab the radio.","task":"Say the radio call in one or two sentences that lead with the hazard and where it is.","tips":["Hazard and location first: open floor hole, second floor, east side.","Then the ask: needs a cover now, keep people out.","Safety calls have no room for warm-up."],"focus":["clarity","impact"],"placeholder":"Open floor hole second floor east side, by the duct chase — needs a cover before anyone else goes up."},
    {"id":"lead-constr-early-09","level":"early","profession":"construction","title":"The supply-house call","scenario":"You're calling the supply house to get a 3-inch ABS fitting delivered to site today. You usually open these calls with small talk and the whole job history before saying what you need.","task":"Write your opening two sentences that lead with the order and the deadline.","tips":["Open with the part and when you need it.","Account number and site address are the support details.","Friendly is fine — but the ask goes first."],"focus":["clarity","concision"]},
    {"id":"lead-constr-early-10","level":"early","profession":"construction","title":"End-of-day text to the office","scenario":"The office wants a one-line end-of-day text from every service tech. Today: furnace repair done at the Hendersons', but you couldn't finish the second call because the part isn't in stock. Your draft is six lines long.","task":"Write a 1-2 sentence end-of-day text that leads with done and not-done.","tips":["Line one: what's finished, what isn't, why in three words.","The office schedules tomorrow off this text — give them the verdict.","Details can wait for the work order notes."],"focus":["concision","structure"],"placeholder":"Henderson furnace done. Second call needs a part — ordering tomorrow AM."},
    {"id":"lead-constr-early-11","level":"early","profession":"construction","title":"The homeowner wants a change","scenario":"Mid-job, the homeowner asks you to move a planned outlet to the other side of the fireplace. It's doable but it's extra wire and time, and you can't approve changes. Your message to the foreman buries the decision under the backstory.","task":"Write a message that leads with the decision needed: approve the change or not.","tips":["First line: homeowner wants X moved — do we do it?","Give the cost in one phrase: extra hour, more wire.","Make it a yes/no he can answer between calls."],"focus":["clarity","structure"]},
    {"id":"lead-constr-early-12","level":"early","profession":"construction","title":"Dead hammer drill","scenario":"Your hammer drill died halfway through drilling anchors, and it's the only one on site. Rental place is ten minutes away. Your text to the foreman starts with how many anchors you'd finished.","task":"Write a text that leads with the problem and your proposed fix.","tips":["Problem first: drill's dead, work is stopped.","Then your suggestion: rent one down the road, back in twenty.","Bring a fix, not just a problem — but state the problem first."],"focus":["clarity","impact"],"placeholder":"Hammer drill just died and it's our only one — OK if I grab a rental down the street?"},
    {"id":"lead-constr-early-13","level":"early","profession":"construction","title":"Calling in sick","scenario":"You woke up with a fever and can't make it to site. The crew is pouring footings today and your absence matters. Your draft text apologizes for two sentences before saying you're out.","task":"Write a 1-2 sentence text that leads with the fact you're out today.","tips":["First words: I'm out sick today.","Then what it affects: pour day, who could cover.","Apology is one word, not a paragraph."],"focus":["concision","clarity"]},
    {"id":"lead-constr-early-14","level":"early","profession":"construction","title":"The job is running long","scenario":"The service call the office booked for two hours is turning into a five-hour job — the valve is seized and access is tight. The scheduler needs to know now, because your 1 p.m. call will have to move.","task":"Write a text to the office that leads with the schedule impact.","tips":["Lead with what they must act on: 1 p.m. call needs to move.","Then the reason, one sentence.","The earlier you flag it, the more options they have — say so plainly."],"focus":["impact","clarity"],"placeholder":"This job's going to 5 hours, not 2 — my 1pm needs to be moved or covered."},
    {"id":"lead-constr-early-15","level":"early","profession":"construction","title":"Rot behind the tub wall","scenario":"You opened the tub wall to replace the mixing valve and found the studs black with rot around the old leak. That's beyond your scope and changes the job. You're about to call the foreman and you tend to narrate the demo first.","task":"Write the first two sentences of the call: the finding and what it means for the job.","tips":["Lead with the finding: rotten studs behind the tub, worse than quoted.","Then the consequence: job scope just changed, homeowner needs a call.","Save how you found it for question time."],"focus":["clarity","impact"]},
    {"id":"lead-constr-early-16","level":"early","profession":"construction","title":"Asking the tapers to move their stack","scenario":"The drywall crew stacked sheets in front of the electrical panel you need to work in all afternoon. You need it moved, and you're heading over to ask their lead. You don't want it to sound like a complaint session.","task":"Write what you'd say in 1-2 sentences, ask first, reason second.","tips":["Lead with the ask: can that stack move a few feet left?","Reason in one phrase: I'm in that panel all afternoon.","Friendly and specific beats hinting."],"focus":["clarity","audience"],"placeholder":"Any chance your crew can shift that stack a few feet off the panel?"},
    {"id":"lead-constr-early-17","level":"early","profession":"construction","title":"The job-log entry that hides the issue","scenario":"You're filling out the daily log in the company app. The one thing tomorrow's crew must know: the shutoff valve for unit 4 doesn't hold, so the riser has to be drained before any work. Your draft buries that under a list of tasks done.","task":"Write a log entry whose first line is the warning, then the day's summary.","tips":["The log's first line is the one people actually read — put the hazard there.","Label it plainly: DO NOT trust the unit 4 shutoff.","Completed tasks go after, in a short list."],"focus":["structure","impact"],"placeholder":"HEADS UP: unit 4 shutoff doesn't hold — drain the riser before opening anything."},
    {"id":"lead-constr-early-18","level":"early","profession":"construction","title":"Running late to the service call","scenario":"Traffic has you thirty minutes behind for a 9 a.m. service call at a customer's house. You're calling to let them know. Your habit is to explain the highway situation before saying the new arrival time.","task":"Write the first sentence of the call: new time, then a short apology.","tips":["New time first: I'll be there at 9:30.","Apology second, one sentence, no traffic story.","They're planning their morning around your first sentence."],"focus":["clarity","concision"]},
    {"id":"lead-constr-early-19","level":"early","profession":"construction","title":"Warranty callback update","scenario":"You went back to the Moreau job to check a warranty complaint about a cold bedroom. The finding: a damper was closed, fixed in ten minutes, no fault in the install. The office wants to close the ticket and your draft tells the whole visit story first.","task":"Write a 2-sentence update that leads with the resolution.","tips":["Lead with the verdict: fixed, damper was closed, no defect.","Then the one-line detail for the file.","Office reads dozens of these — reward the skim."],"focus":["concision","clarity"],"placeholder":"Moreau callback resolved — closed damper, ten-minute fix, no install issue."},
    {"id":"lead-constr-early-20","level":"early","profession":"construction","title":"Asking for the Friday off","scenario":"You need next Friday off for your licensing exam. It's also a delivery day on site. Your draft message to the foreman spends four sentences on how you know it's bad timing before making the request.","task":"Write a request that leads with the ask and the date.","tips":["First sentence: I need Friday the 12th off — licensing exam.","Then the one thing you'll do about the timing: prep the delivery list Thursday.","A clear ask with a plan is easier to say yes to."],"focus":["clarity","structure"]},
    {"id":"lead-constr-early-21","level":"early","profession":"construction","title":"What's this going to cost me?","scenario":"You've diagnosed the water heater: it needs a new gas valve. The homeowner is standing next to you asking what it'll cost. You know it's about $450 parts and labor. You tend to start with everything you checked first.","task":"Answer in 1-2 sentences that lead with the number.","tips":["Number first: about $450, parts and labor.","Then what it covers, in one phrase.","Walking through your diagnosis first sounds like stalling."],"focus":["precision","clarity"],"placeholder":"About $450 all-in — that's the new gas valve plus my time to swap it."},
    {"id":"lead-constr-early-22","level":"early","profession":"construction","title":"The concrete truck window","scenario":"You're the one coordinating with the batch plant. The forms will be ready by 10:30, not 9:00 like originally booked. You need the dispatcher to push the truck, and every minute of warm-up costs you the slot.","task":"Write what you'd say to the dispatcher, ask first.","tips":["Lead with the change: push our truck to 10:30.","Give the job name and order number right after.","Confirm the new time back before you hang up."],"focus":["clarity","precision"]},
    {"id":"lead-constr-early-23","level":"early","profession":"construction","title":"Wrong material on the truck","scenario":"The lumber delivery just arrived with 2x8s where the order said 2x10s for the floor joists. The driver is waiting and wants a signature. You need the foreman's call fast, and your thumbs want to type the whole delivery saga.","task":"Write a text that leads with the problem and the decision needed while the driver waits.","tips":["First line: delivery is wrong — 2x8 instead of 2x10 joists.","Then the live decision: sign for the rest and refuse those, or refuse it all?","Say the driver is waiting so he knows the clock is running."],"focus":["clarity","impact"],"placeholder":"Delivery has 2x8s where we ordered 2x10 joists — driver's waiting. Refuse just those or the whole load?"},
    {"id":"lead-constr-early-24","level":"early","profession":"construction","title":"Clarifying before you close the wall","scenario":"The plans show a receptacle height that doesn't match what the foreman said on Monday. You're about to close walls, so guessing wrong means rework. Your text drafts keep opening with an apology for asking.","task":"Write a question-first text that names the conflict and asks which one wins.","tips":["Lead with the question: plans say 18 inches, you said 16 — which do I follow?","Name why it's urgent: closing walls after lunch.","Asking before the wall closes is cheap; after, it's a demo."],"focus":["clarity","precision"],"placeholder":"Plans show plugs at 18\" but Monday you said 16\" — which one before I close these walls?"},
    {"id":"lead-constr-early-25","level":"early","profession":"construction","title":"You found someone else's problem","scenario":"Prepping to insulate, you noticed a plumbing vent that isn't glued — the joint is dry-fit and will leak sewer gas once the wall is closed. Not your trade, not your mistake, but you're the one who saw it. You want to flag it without sounding like you're ratting anyone out.","task":"Write a message to the foreman that leads with the finding, plain and neutral.","tips":["Lead with what and where: dry-fit vent joint, second-floor bath wall.","Stick to what you saw — no guesses about who or why.","Flag it before the wall closes; that's the whole point of saying it now."],"focus":["clarity","impact"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-constr-early-01","level":"early","profession":"construction","title":"Why the power's going off","scenario":"You're about to kill the main breaker for two hours to swap the panel. The homeowner works from home and is on video calls. Your first instinct is to say \"I'm pulling the meter and re-terminating the service conductors.\"","task":"Tell the homeowner what's happening in 2-3 sentences they can plan around.","tips":["Lead with what it means for them: no power, two hours, starting at 1.","Skip the terminology — meter, conductors, terminations mean nothing here.","Tell them what to do: save work, charge the laptop now."],"focus":["audience","clarity"],"placeholder":"Your power will be off from about 1 to 3 while I swap the panel —"},
    {"id":"audience-constr-early-02","level":"early","profession":"construction","title":"Translate the leak","scenario":"You found the bathroom leak: a pinholed copper line inside the wall, and you'll sweat in a new section. The homeowner asks what's wrong. \"Pinhole in the supply line, I'll cut it out and sweat a coupling in\" will earn a blank stare.","task":"Explain the problem and fix in 2-3 sentences a homeowner understands.","tips":["Name the symptom and cause in plain words: a small hole wore through a water pipe.","Describe the fix by outcome: replace that section, leak stops today.","Say what it means for them: water off for an hour, small wall patch after."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-03","level":"early","profession":"construction","title":"The parts text the office can act on","scenario":"You need the office to order a part. Your draft says \"need the 3/4 sweat x 3/4 FIP ball valve, full port, lead-free.\" The person ordering isn't a plumber — she needs something she can read to the supplier or type into a search.","task":"Write a parts request the office can order from without calling you back.","tips":["Give the exact spec, but also say what it's for so a substitute question makes sense.","Add supplier and quantity — remove every reason to ping you back.","One message, everything needed: part, count, job name, when."],"focus":["audience","precision"],"placeholder":"Please order from Wolseley: 1x lead-free 3/4\" ball valve, sweat x FIP, full port — for the Chen repipe, need it Thursday."},
    {"id":"audience-constr-early-04","level":"early","profession":"construction","title":"Telling the framer what you need","scenario":"You need the framing crew to add blocking so you can mount a heavy vanity light bracket. If you say \"I need backing at 84 inches on center in bay 3,\" that works — but you also need them to care, because they're moving to the garage tomorrow.","task":"Write 2-3 sentences to the framing lead: the request in their terms, plus why it can't wait.","tips":["Speak framer: blocking height, which wall, which bay.","The stake is theirs too: no blocking today means a callback for their crew.","Ask for a time: can it happen before you move to the garage?"],"focus":["audience","impact"]},
    {"id":"audience-constr-early-05","level":"early","profession":"construction","title":"First-day helper instructions","scenario":"A brand-new helper starts today, and you're told to get him prepping your material. Your usual shorthand — \"kit out the home runs for the second floor\" — assumes months of context he doesn't have.","task":"Give the task in 3-4 sentences that a first-day helper can follow without guessing.","tips":["Drop the crew shorthand; name real objects: wire rolls, boxes, the second-floor plan sheet.","One task with a visible endpoint: when this cart looks like that, come find me.","Tell him what to do when stuck: ask, don't guess."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-06","level":"early","profession":"construction","title":"Why the quote went up","scenario":"Copper prices jumped and the repipe quote from March is now $600 more in materials. The homeowner asks why, sounding annoyed. \"Commodity pricing on copper moved\" won't land; neither will a shrug.","task":"Explain the increase in 2-3 sentences a homeowner accepts as fair.","tips":["Translate to their world: the pipe itself costs more to buy than in March.","Give the number and where it comes from — materials, not your pocket.","Offer the check: happy to show the supplier's price sheet."],"focus":["audience","precision"],"placeholder":"The pipe itself got more expensive — copper's up since we quoted in March, and that's the whole $600."},
    {"id":"audience-constr-early-07","level":"early","profession":"construction","title":"One message, one reader","scenario":"The furnace part is delayed and the install slips two days. You start writing one message to send both to the homeowner and the foreman. Halfway in you realize they need totally different things: she needs heat options; he needs the schedule impact.","task":"Pick ONE of them and write the 2-3 sentence message for that reader only.","tips":["Choose the primary audience and commit — the other gets their own message.","Homeowner version: what it means for her house and heat.","Foreman version: dates, crew impact, what to reshuffle."],"focus":["audience","structure"]},
    {"id":"audience-constr-early-08","level":"early","profession":"construction","title":"Email to the GC's project manager","scenario":"The general contractor's PM emailed asking for status on your electrical rough-in. She runs eleven jobs, doesn't know a home run from a hole saw, and mostly needs to know: on schedule or not, and anything that moves her critical path.","task":"Write a 3-4 sentence status email pitched at a busy PM.","tips":["Lead with the schedule answer: on track for Friday inspection.","Translate work into milestones she tracks, not tasks you did.","Flag the one dependency: drywall can't start until the inspection passes."],"focus":["audience","structure"],"placeholder":"Rough-in is on track — we'll be ready for Friday's inspection."},
    {"id":"audience-constr-early-09","level":"early","profession":"construction","title":"Don't use that bathroom","scenario":"You've pulled the toilet and the flange is open to the sewer line until tomorrow. The family is home tonight. \"The closet flange is open so the stack's unsealed\" won't stop a half-asleep kid at 2 a.m.","task":"Write the 2-3 sentence warning you'd give (and the note you'd tape to the door).","tips":["Say the rule first, bluntly: nobody uses this bathroom until I'm back.","Give the reason in their terms: open sewer pipe — smell and germs.","Cover the failure case: door note, and which bathroom to use instead."],"focus":["audience","impact"],"placeholder":"Please keep everyone out of this bathroom until tomorrow — the sewer pipe is open under the floor."},
    {"id":"audience-constr-early-10","level":"early","profession":"construction","title":"Why the inspector has to come","scenario":"The homeowner wants you to close the ceiling today so painting can start. The wiring needs inspection first, and \"it has to pass rough-in before cover\" sounds like red tape to her.","task":"Explain in 2-3 sentences why the wall stays open, in terms of her interest.","tips":["Frame it as protecting her: the inspection catches problems while they're cheap to fix.","Name the real risk of skipping: failed final, tearing out fresh paint.","Give the timeline so it feels finite: inspector Thursday, close-up Friday."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-11","level":"early","profession":"construction","title":"Talking feasibility with the designer","scenario":"The kitchen designer wants the island pendant lights exactly over the counter centerline, but there's a joist directly in the way at one spot. She doesn't know joists; she knows sightlines and symmetry.","task":"Explain the constraint and offer options in 3-4 sentences in her terms.","tips":["Translate the joist into her language: a structural beam sits exactly where the middle light wants to go.","Give options in design terms: shift all three lights 2 inches, or offset one.","Ask for her call — she owns the look, you own the wiring."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-12","level":"early","profession":"construction","title":"Voicemail for the tenant","scenario":"You're doing a repair in an occupied rental tomorrow. The landlord gave you the tenant's number. The tenant didn't hire you, may be wary, and just needs to know who's coming, when, and what to expect.","task":"Write a 3-4 sentence voicemail script for the tenant.","tips":["Identify yourself and who sent you in the first sentence.","Their concerns first: time window, how long, which room, water off or not.","Give a callback number and keep the tone easy, not official."],"focus":["audience","clarity"],"placeholder":"Hi, this is Sam from Ridgeline Plumbing — your landlord booked us to fix the kitchen leak tomorrow."},
    {"id":"audience-constr-early-13","level":"early","profession":"construction","title":"The outlet that keeps 'breaking'","scenario":"The customer says the bathroom outlet \"keeps breaking.\" It's the GFCI doing its job — tripping when their old hair dryer leaks current. They're ready to demand a new outlet that \"won't break.\"","task":"Explain in 2-3 sentences what's actually happening, without making them feel dumb.","tips":["Reframe: the outlet isn't broken, it's protecting you — that's its whole job.","Use a comparison they know: like a smoke alarm, annoying only when there's something real.","Point at the actual cause and next step: try another dryer, or I can test this one now."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-14","level":"early","profession":"construction","title":"Hot work, plain words","scenario":"You need to solder pipe in a ceiling space at a commercial site, which means a hot-work permit and a fire watch. The site super is new and rushes you with \"just get it done.\" He needs to hear what it involves in schedule terms, not code citations.","task":"Explain in 2-3 sentences what you need and why, pitched at a schedule-focused super.","tips":["Lead with what it costs him: 30 minutes to set up, one person on fire watch.","One-line why: open flame near dust and wood — this is the no-fire routine.","Make the ask concrete: sign the permit and give me a watch, torch is lit by 10."],"focus":["audience","impact"]},
    {"id":"audience-constr-early-15","level":"early","profession":"construction","title":"Note for the next crew","scenario":"You're leaving a service job unfinished — parts on order — and a different tech will finish it next week. Whatever you know that isn't written down is lost. \"Usual setup, finish the swap\" helps nobody.","task":"Write a 3-4 sentence handoff note assuming the reader has never seen this job.","tips":["Assume zero context: address quirks, where the shutoff hides, what's already done.","Name the exact next step and where the parts will be.","Include the landmine: the union above the tank is seized — cut, don't wrench."],"focus":["audience","structure"],"placeholder":"For whoever picks this up: valve swap is half done — old valve out, new one arrives Tuesday to the office."},
    {"id":"audience-constr-early-16","level":"early","profession":"construction","title":"The ducts are supposed to do that","scenario":"A homeowner calls, worried the new ductwork is \"banging\" at night. It's normal expansion ticking as metal heats and cools. \"That's just thermal expansion of the trunk line\" is accurate and useless to a worried person at 11 p.m.","task":"Reassure and explain in 2-3 sentences a non-technical homeowner relaxes to.","tips":["Reassure first: it's normal, nothing is broken, nothing will catch fire.","Explain with a familiar image: metal stretches slightly as it warms, like a lid popping.","Leave a door open: if it becomes a rattle or gets louder, call and I'll look."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-17","level":"early","profession":"construction","title":"Explaining the violation","scenario":"On a service call you found the previous owner's wiring in the garage is illegal and genuinely unsafe — undersized wire on an oversized breaker. The homeowner didn't cause it and might hear a code citation as an upsell.","task":"Explain the problem in 2-3 sentences that inform without scaring or selling.","tips":["Plain mechanism: the wire is too small for the breaker, so it can overheat before the breaker trips.","Say what it isn't: not your fault, not an emergency tonight, but not something to leave.","Separate the information from the sale: here's the fix and price when you're ready."],"focus":["audience","clarity"],"placeholder":"I found something in the garage you should know about — not urgent tonight, but worth fixing."},
    {"id":"audience-constr-early-18","level":"early","profession":"construction","title":"The dust question","scenario":"A mother asks whether the renovation dust is safe for her toddler, especially with sanding starting tomorrow. You know the plan — plastic barriers, a fan blowing out the window, daily cleanup — but she's asking about her kid, not your equipment.","task":"Answer in 2-3 sentences that speak to her actual worry.","tips":["Answer the worry first: the work area is sealed off from where your son plays.","Describe protections by what they do for her, not by product names.","Give her a role: anything you notice getting through, tell me same day."],"focus":["audience","impact"]},
    {"id":"audience-constr-early-19","level":"early","profession":"construction","title":"You can't just move that wall","scenario":"The homeowner, tape measure in hand, asks you to \"just take out\" the wall between kitchen and dining room while you're there. You can see it's carrying the ceiling joists. You're not the one to authorize or price it, but you are the one standing there.","task":"Respond in 2-3 sentences: why it's a bigger deal, in her terms, without killing the idea.","tips":["Give the plain-words reason: that wall is holding up the floor above.","It's possible, just a different project: beam, engineer, permit.","Route it right: the office can price it properly — want me to flag it?"],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-20","level":"early","profession":"construction","title":"Telling the scheduler the truth about duration","scenario":"The office keeps booking water heater swaps as 2-hour slots. In these older houses they're honestly 4 hours — hauling, draining, venting, cleanup. The scheduler isn't a plumber and books what the system template says.","task":"Write a message to the scheduler that changes how she books these, in her terms.","tips":["Speak scheduler: slot length, callbacks, angry-customer calls — not venting details.","Give the breakdown fast: haul-out, drain, fit, test — 4 hours in pre-1980 houses.","Propose the rule she can apply: older house plus stairs equals 4-hour slot."],"focus":["audience","precision"],"placeholder":"Can we book heater swaps in older houses as 4-hour slots? Here's what the 2-hour bookings are costing us —"},
    {"id":"audience-constr-early-21","level":"early","profession":"construction","title":"Rough-in versus finish, for a first-timer","scenario":"First-time renovators keep asking why you're \"done\" but nothing works yet. You've roughed in the plumbing; fixtures come after drywall and paint. They see pipes sticking out of open walls and a plumber packing up.","task":"Explain rough-in vs finish in 2-3 sentences using their kitchen, not trade terms.","tips":["Use a build-order picture: pipes in the walls now, taps and toilet after the walls close.","Anchor it to what they'll see: I disappear for two weeks, then return when paint's done.","Tell them what works meanwhile: everything upstairs stays on."],"focus":["audience","clarity"]},
    {"id":"audience-constr-early-22","level":"early","profession":"construction","title":"Why we shouldn't pour today","scenario":"The client wants the driveway poured this week, but it's dropping to -8 at night and proper cold-weather curing would need blankets and additives that add cost. \"Curing hydration stalls below 5 degrees\" won't move him; cracked concrete in April might.","task":"Make the case for waiting (or paying for cold-weather protection) in 2-3 sentences he cares about.","tips":["Lead with his stake: pour it cheap this week and it can crack by spring — on his dime.","Give two honest options with prices: wait two weeks free, or blankets and additive for $X.","Numbers and outcomes, not chemistry."],"focus":["audience","impact"]},
    {"id":"audience-constr-early-23","level":"early","profession":"construction","title":"Two readers, one text thread","scenario":"The group text has both the foreman and the homeowner in it — the homeowner added herself. You need to report that today's tile work stops because the wrong thinset was delivered. The foreman needs the supply detail; the homeowner will panic at \"work stopped.\"","task":"Write the one message you'd actually send to that thread.","tips":["Pick the primary reader — the homeowner — and let the foreman get details separately.","Lead with reassurance shaped as fact: small supply mix-up, fixed by tomorrow, schedule holds.","Keep the trade detail out of the shared thread; text the foreman the spec directly."],"focus":["audience","structure"]},
    {"id":"audience-constr-early-24","level":"early","profession":"construction","title":"Walking through the change order","scenario":"The office emailed the homeowner a change order for the extra bathroom fan and asked you to get it signed while on site. The homeowner squints at the form: line items, terms, a price. She'll sign if she understands it — from you, in person.","task":"Explain the change order in 3-4 spoken sentences before handing over the pen.","tips":["Say what it is in one line: this adds the fan you asked for to the contract — nothing else changes.","Walk the price: part, labor, the new total.","Invite the question now: better to ask me than wonder later."],"focus":["audience","clarity"],"placeholder":"This is just the paperwork for the fan you asked about Tuesday —"},
    {"id":"audience-constr-early-25","level":"early","profession":"construction","title":"Passing the engineer's answer down","scenario":"The structural engineer told you on the phone: \"You can notch the joist up to a sixth of the depth in the outer third of the span, no notching in the middle third.\" Your foreman just needs to know: can we run the pipe where we planned or not?","task":"Relay the answer to the foreman in 1-2 sentences at the altitude he needs.","tips":["Lead with the verdict for YOUR spot: yes, our location is fine — or no, we move it.","Keep the rule handy in one short line in case the spot shifts.","Don't re-perform the whole engineering call; answer the live question."],"focus":["audience","concision"],"placeholder":"Engineer says we're good where we planned —"}
  ],
  "structure-that-carries": [
    {"id":"structure-constr-early-01","level":"early","profession":"construction","title":"The punch list nobody can work from","scenario":"After the walkthrough you have fourteen scribbled items: sticky door, missing outlet cover, paint touch-up in three rooms, a drip under the sink, loose railing, and more. Sent as-is, it's a wall of chaos that three different trades have to untangle.","task":"Reorganize the fourteen items into 3 or fewer labeled groups someone can act on.","tips":["Group by who fixes it: painter, plumber, carpenter — not by room you noticed it in.","Order groups by urgency; the drip beats the paint.","One line per item: location plus problem."],"focus":["structure","clarity"]},
    {"id":"structure-constr-early-02","level":"early","profession":"construction","title":"Your plan for the day, in three buckets","scenario":"The foreman asks each person at the huddle for their plan. You have nine little tasks in your head — pull wire in two bedrooms, set boxes, label the panel, help unload at ten, chase a missing part. Listed raw, it sounds like noise.","task":"Give your day as one headline plus 3 buckets, out loud in under 30 seconds.","tips":["Headline first: bedrooms wired and panel labeled by end of day.","Bucket the nine tasks under morning, after-delivery, and if-time-allows.","Three buckets max — a fourth means two should merge."],"focus":["structure","concision"],"placeholder":"By end of day both bedrooms are wired and the panel's labeled. Morning: ..."},
    {"id":"structure-constr-early-03","level":"early","profession":"construction","title":"SCQA for a problem the foreman doesn't know yet","scenario":"The spec calls for recessed lights in a ceiling that turns out to have no depth — old solid-wood blocking everywhere. You need the foreman to grasp the situation, why it's a problem now, and what you're asking, in one tight message.","task":"Write the message as Situation, Complication, Question, Answer — 4 sentences.","tips":["Situation: what was planned, one line.","Complication: what you found that breaks the plan.","Question and your proposed answer: switch to low-profile fixtures — approve?"],"focus":["structure","clarity"],"placeholder":"Plan calls for six recessed lights in the den ceiling. Problem: there's solid blocking —"},
    {"id":"structure-constr-early-04","level":"early","profession":"construction","title":"PREP: replace the whole panel?","scenario":"The homeowner asks you point-blank: \"Should we just replace the whole electrical panel?\" You believe yes — it's full, it's 40 years old, and every future job fights it. You tend to think out loud and circle before landing.","task":"Answer aloud using PREP: Point, Reason, Example, Point — 4-5 sentences.","tips":["Point first: yes, I'd replace it.","One reason, one concrete example: adding your dryer circuit today took three hours because the panel is full.","Restate the point with the action: replace it now while the wall's already open."],"focus":["structure","clarity"]},
    {"id":"structure-constr-early-05","level":"early","profession":"construction","title":"One order, three suppliers","scenario":"Your materials list for next week has eleven items across three suppliers — pipe from the plumbing house, lumber from the yard, fasteners from the box store — and two items are urgent. One long list in a text will get half-ordered.","task":"Structure the request so the office can place three clean orders, urgent items unmissable.","tips":["Group by supplier — that's how the reader acts on it.","Mark the two urgent items at the top, not buried in their groups.","Give each group a deadline, not the whole list one vague 'ASAP'."],"focus":["structure","precision"]},
    {"id":"structure-constr-early-06","level":"early","profession":"construction","title":"Done, doing, stuck","scenario":"You're off for two days and another apprentice covers your work. Your brain dump has fifteen facts in random order — some finished, some half-done, one blocked on parts. He'll read it once, on his phone, at 6:45 a.m.","task":"Write the handoff under three headings: DONE / IN PROGRESS / BLOCKED.","tips":["The three headings do the organizing — keep every line under the right one.","In-progress lines need a next step, not just a status.","Blocked lines need who or what they're waiting on."],"focus":["structure","clarity"],"placeholder":"DONE: kitchen small-appliance circuits, tested. IN PROGRESS: ..."},
    {"id":"structure-constr-early-07","level":"early","profession":"construction","title":"Problem, options, recommendation","scenario":"The furnace repair has two honest paths: a $700 control board on a 15-year-old unit, or a new furnace. The homeowner asked you to \"explain the options.\" Unstructured, this turns into a fifteen-minute ramble that ends in confusion.","task":"Deliver it in three labeled moves: the problem, the two options with numbers, your recommendation.","tips":["One sentence of problem — resist re-telling the diagnosis.","Options side by side with the same shape: cost now, expected life, risk.","End on one recommendation and why, not 'up to you' alone."],"focus":["structure","audience"]},
    {"id":"structure-constr-early-08","level":"early","profession":"construction","title":"Three problems, one text","scenario":"Driving between calls you need to tell the office three unrelated things: a customer wants a quote for extra work, your van's brakes are grinding, and Thursday's job has no permit posted yet. Mashed into one paragraph, at least one gets missed.","task":"Write one text structured so all three items get acted on.","tips":["Number them — 1, 2, 3 — with the most time-sensitive first.","One line each: the fact plus what you need done.","Say who each item is for if different people handle them."],"focus":["structure","concision"],"placeholder":"Three things: 1) Thursday's job — no permit posted yet, can someone check?"},
    {"id":"structure-constr-early-09","level":"early","profession":"construction","title":"The sequencing pitch","scenario":"You need the tile setter to wait one day so you can move a floor drain first — otherwise he tiles over it Tuesday and you cut his fresh work Wednesday. Your argument has to carry its own logic: what, why, in what order.","task":"Make the case in 3-4 sentences ordered so the logic carries itself.","tips":["State the governing idea first: drain moves before tile, or we redo tile.","Then the sequence as steps with days attached.","Close with what you need from him: give me Tuesday, you start Wednesday clean."],"focus":["structure","impact"]},
    {"id":"structure-constr-early-10","level":"early","profession":"construction","title":"Toolbox talk: one idea, three points","scenario":"The foreman handed you Friday's five-minute toolbox talk on ladder safety. The company handout has nineteen bullet points. Reading all nineteen guarantees nobody remembers one.","task":"Plan the talk as one governing idea supported by exactly three points.","tips":["Pick the one idea: every ladder fall this year started with a setup shortcut.","Choose the three points that serve it; let the other sixteen go.","Signpost out loud: 'Three things — footing, angle, and three points of contact.'"],"focus":["structure","impact"],"placeholder":"One thing today: ladder falls start at setup. Three checks —"},
    {"id":"structure-constr-early-11","level":"early","profession":"construction","title":"Walkthrough notes the super can use","scenario":"You walked the third floor with the site super and he asked you to send him \"what we saw.\" Your phone notes are twenty lines in walking order — a mix of your trade's issues, other trades' issues, and things that are fine.","task":"Restructure the notes into a message with one governing headline and clear groups.","tips":["Headline the overall verdict: third floor is 90% ready — three holdups.","Group by trade or by 'blocking vs cosmetic', not by the path you walked.","Cut the 'things that are fine' unless he asked for them."],"focus":["structure","clarity"]},
    {"id":"structure-constr-early-12","level":"early","profession":"construction","title":"Warranty visit, findings grouped","scenario":"On a one-year warranty visit you found six issues: two are your company's to fix, three are normal wear the homeowner owns, one is another trade's. Your report will go to the office AND drive what the homeowner is told.","task":"Write the findings grouped by who owns them, with a one-line summary up top.","tips":["The grouping IS the message: ours / homeowner's / other trade's.","Top line: six findings, two ours, both minor.","Within each group, order by cost or urgency."],"focus":["structure","precision"]},
    {"id":"structure-constr-early-13","level":"early","profession":"construction","title":"PREP: why is this taking longer?","scenario":"The homeowner asks, with an edge: \"Why is this taking longer than you said?\" The honest answer involves hidden knob-and-tube wiring, but delivered as a wandering story it sounds like excuses.","task":"Answer aloud with PREP — Point, Reason, Example, Point — in under 45 seconds.","tips":["Point: we found old wiring that has to come out — that's the extra two days.","Reason and example: it's spliced into places we can't legally leave it, like the hall ceiling I opened Tuesday.","Land the point again with the new date, said plainly."],"focus":["structure","clarity"]},
    {"id":"structure-constr-early-14","level":"early","profession":"construction","title":"The restock list that works","scenario":"Your service van is running dry and the office asked for a restock list. Brain-dumped, it's thirty items in memory order. The person filling it will shop three different aisles and suppliers, and will miss things in a jumble.","task":"Organize the thirty items into groups that match how they'll be gathered.","tips":["Group by where they're bought or stored: fittings, electrical, consumables.","Quantities on every line — 'more screws' fills nothing.","Flag the five 'can't work without' items in their own top group."],"focus":["structure","precision"]},
    {"id":"structure-constr-early-15","level":"early","profession":"construction","title":"The incident, in order","scenario":"A grinder kicked back and cut a coworker's glove — no injury, close call. The safety officer needs it written up. Rattled, your draft mixes what happened, what you think caused it, and what should change, all in one tangle.","task":"Write the report in three parts and in time order: what happened, contributing factors, what should change.","tips":["Part one is only the sequence — facts in time order, no opinions.","Factors come second: guard position, cord placement, rushing before break.","Recommendations last, tied to a factor each."],"focus":["structure","precision"],"placeholder":"At about 10:15, D. was cutting rebar stubs when the grinder caught and kicked left —"},
    {"id":"structure-constr-early-16","level":"early","profession":"construction","title":"Now, later, or never","scenario":"During the reno the homeowner keeps adding wishes: pot lights in the hall, a heated floor, a smart thermostat, an outlet in the pantry, a garage subpanel. Some fit now, some belong after this job, one is a bad idea. It's all sitting in a text thread.","task":"Sort the wish list into three labeled buckets — do now, do later, don't do — with one line of reasoning each.","tips":["The buckets carry the message; the reasoning is one line each, not a debate.","'Now' means cheaper while walls are open — say that plainly.","'Don't do' needs a respectful why: the garage panel needs a service upgrade first."],"focus":["structure","audience"]},
    {"id":"structure-constr-early-17","level":"early","profession":"construction","title":"Progress photos with a spine","scenario":"The office wants weekly progress photos for the client file. You have eleven photos from today. Uploaded with names like IMG_4471, they're useless in a month — or in a dispute.","task":"Write captions and an ordering scheme so the photo set tells one clear story.","tips":["Order photos to tell the job's story: before, during, done — not camera-roll order.","Each caption: location, what it shows, date. One line.","Lead the set with a one-line summary caption for the folder."],"focus":["structure","precision"]},
    {"id":"structure-constr-early-18","level":"early","profession":"construction","title":"Two routes, laid side by side","scenario":"The new gas line can run through the basement ceiling (cleaner, slower, more holes to patch) or along the exterior wall (faster, visible pipe). The homeowner has to pick. Explained as one long story, the options blur together.","task":"Present both options in parallel structure: same categories, same order, then your lean.","tips":["Pick your comparison categories — cost, time, looks — and use them for BOTH options in the same order.","Keep the options the same length; lopsided detail reads as steering.","State your lean at the end, with the one deciding factor."],"focus":["structure","clarity"]},
    {"id":"structure-constr-early-19","level":"early","profession":"construction","title":"The daily report that reads itself","scenario":"The company app has one big text box for the daily report, and everyone types a paragraph. Yesterday's entry got the crew in trouble because a delay was buried mid-paragraph. You want a format the office can skim in ten seconds.","task":"Write today's report with your own labeled structure: progress, issues, needs, tomorrow.","tips":["Invent the headings the box doesn't give you — labels beat paragraphs.","Issues get their own line each, never blended into progress.","'Tomorrow' is one line: what happens next and what it depends on."],"focus":["structure","concision"],"placeholder":"PROGRESS: unit 2 rough-in complete. ISSUES: ..."},
    {"id":"structure-constr-early-20","level":"early","profession":"construction","title":"Three questions, numbered","scenario":"You have three questions for the foreman before he disappears into a meeting: panel location in the garage, whether the owner approved the extra outlet, and if Friday's inspection is booked. Asked as a blob, you'll get one answer and two shrugs.","task":"Write the message so each question gets its own answer.","tips":["Number the questions and make each one self-contained.","Order them by what blocks you soonest.","Make each answerable in five words or less — yes, no, a place, a date."],"focus":["structure","clarity"],"placeholder":"Three quick ones before your meeting: 1) Garage panel — left wall or back wall?"},
    {"id":"structure-constr-early-21","level":"early","profession":"construction","title":"SCQA for renting the lift","scenario":"Hand-carrying sheet goods to the third floor is eating hours and backs. A material lift rents for $180 a day and would pay for itself in a day and a half. You want to pitch the foreman without it sounding like whining about hard work.","task":"Write the pitch as SCQA in 4 sentences.","tips":["Situation: what the crew is doing now, neutrally.","Complication: the cost in hours — put a number on the carrying.","Question, then your answer: rent the lift for two days; it saves more than it costs."],"focus":["structure","impact"]},
    {"id":"structure-constr-early-22","level":"early","profession":"construction","title":"Teaching lockout in steps","scenario":"You're showing the new helper how to lock out a circuit before working on it. This is the one procedure where 'roughly in this order' isn't good enough. Your explanation has to carry the sequence so he can repeat it alone.","task":"Explain the procedure as numbered steps, each one action, in order — then the check at the end.","tips":["One action per step; if a step has an 'and', split it.","Number out loud: step one, step two — the numbers are handles for memory.","End with the verification step and say why it's the one you never skip."],"focus":["structure","clarity"]},
    {"id":"structure-constr-early-23","level":"early","profession":"construction","title":"Recap of the supplier call","scenario":"You just spent twenty minutes on the phone with the supplier about the backordered fixtures: some ship Friday, some in two weeks, one is discontinued with a substitute offered. The foreman needs this in a form he can act on, not a replay of the call.","task":"Write a recap structured by decision needed, not by conversation order.","tips":["Sort into: no action needed / decision needed / bad news.","The discontinued item is a decision: accept the sub or reselect — put it first.","Dates on every line; 'soon' is not a date."],"focus":["structure","precision"],"placeholder":"Fixture order recap — one decision needed: the hall sconce is discontinued."},
    {"id":"structure-constr-early-24","level":"early","profession":"construction","title":"The quote, broken into parts","scenario":"A neighbor of your current job asked you to quote a small deck repair — your first solo quote. Everything you'd charge is swirling: boards, screws, hauling, your Saturday. One lump number invites haggling; a structured one earns trust.","task":"Write the quote as labeled parts — materials, labor, disposal — with one total.","tips":["Three named buckets, each with its number, then the total.","Round honestly; false precision like $487.63 invites nitpicking anyway.","One line on what's NOT included, so the structure protects you later."],"focus":["structure","precision"]},
    {"id":"structure-constr-early-25","level":"early","profession":"construction","title":"The Friday summary with one spine","scenario":"The foreman wants a short Friday text on your week. You did a dozen things across two sites. A list of twelve is technically complete and completely unreadable. He needs one governing sentence and a few supports.","task":"Write the weekly summary: one governing idea, then up to 3 supporting lines.","tips":["Find the sentence the week adds up to: both units are inspection-ready.","Pick the 3 supports that prove it; drop the other nine things.","If something next week depends on this week, that's your last line."],"focus":["structure","concision"],"placeholder":"Week in one line: both units are ready for Tuesday's inspection."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-constr-early-01","level":"early","profession":"construction","title":"The ten-line text that says one thing","scenario":"Your draft to the foreman: ten lines about the tile delivery, the weather, what the drywallers said, and — buried in line eight — the actual point: the tub surround can't start until Monday. He'll read it at a red light.","task":"Cut the text to 2 sentences that keep only what he must know.","tips":["Find the one sentence the message exists for; everything else auditions to stay.","Weather and hallway chatter don't survive the cut.","If a detail doesn't change what he does Monday, it goes."],"focus":["concision","clarity"],"placeholder":"Tub surround can't start till Monday — tile's delayed to Friday and needs 48hr set."},
    {"id":"concise-constr-early-02","level":"early","profession":"construction","title":"The 20-second voicemail","scenario":"You need to leave the building manager a voicemail: the boiler part arrived, you'll install Thursday morning, and heat will be off 8 to 11. Your last voicemail to him ran two minutes and he stopped listening halfway.","task":"Script a voicemail under 20 seconds with all three facts.","tips":["Name, company, and the point in the first five seconds.","Three facts, three short sentences, then your number.","Say the callback number slowly — it's the only part worth repeating."],"focus":["concision","clarity"]},
    {"id":"concise-constr-early-03","level":"early","profession":"construction","title":"Kill the 'just's","scenario":"Your draft: \"Sorry to bother you, I just had a quick question, if you get a chance, no rush at all, but I was just wondering if maybe the paint schedule could possibly shift...\" You need the painters to start a day later. That's the whole message.","task":"Rewrite without hedges — no just, maybe, possibly, sorry-to-bother.","tips":["Cut every 'just', 'maybe', 'kind of', 'if possible' — then read it again.","Polite and direct coexist: 'Can the painters start Wednesday instead?'","Hedging makes people ignore the request, not like you more."],"focus":["concision","impact"],"placeholder":"Can the painters start Wednesday instead of Tuesday? My inspection moved."},
    {"id":"concise-constr-early-04","level":"early","profession":"construction","title":"The log entry on a diet","scenario":"Your daily log draft: \"Today we proceeded to continue with the ongoing installation of the ductwork in the vicinity of the mechanical room area, and at this point in time it is approximately 75% complete.\" Every phrase has a shorter twin.","task":"Rewrite the entry at half the length with none of the meaning lost.","tips":["'Proceeded to continue with the ongoing installation of' = 'installed'.","'In the vicinity of the mechanical room area' = 'at the mechanical room'.","'At this point in time it is approximately' = 'now about'."],"focus":["concision","precision"],"placeholder":"Mechanical room ductwork about 75% done."},
    {"id":"concise-constr-early-05","level":"early","profession":"construction","title":"Halve the homeowner speech","scenario":"You practiced explaining today's furnace work to the homeowner and it runs three minutes: history of the model, everything you checked, two side stories. She's standing in the doorway holding groceries.","task":"Cut the explanation to 30 seconds: what was wrong, what you did, what's next.","tips":["Three beats only: found, fixed, next.","Cut the diagnostic journey — she needs the destination.","Watch her hands: groceries mean you get four sentences."],"focus":["concision","audience"]},
    {"id":"concise-constr-early-06","level":"early","profession":"construction","title":"Delete the throat-clearing","scenario":"Your email starts: \"I hope this finds you well. I just wanted to reach out and touch base regarding the matter of the upcoming inspection that we discussed previously.\" Two lines gone before any information appears.","task":"Rewrite the opening so the first sentence carries information.","tips":["'I wanted to reach out regarding' is throat-clearing — start with the thing itself.","First sentence test: does it tell them anything? If not, cut until it does.","Warmth can live in the sign-off; the opening belongs to the point."],"focus":["concision","clarity"],"placeholder":"The electrical inspection is confirmed for Thursday at 9."},
    {"id":"concise-constr-early-07","level":"early","profession":"construction","title":"One breath on the radio","scenario":"On a big site, radio discipline matters — long transmissions block the channel. You need to tell the crane crew the load is rigged and clear to lift, east laydown. Your instinct is a full paragraph of context.","task":"Say it in one transmission, one breath.","tips":["Channel protocol: who you're calling, who you are, then the message.","Every word costs airtime someone else might need.","Confirm-worthy facts only: load, status, location."],"focus":["concision","clarity"]},
    {"id":"concise-constr-early-08","level":"early","profession":"construction","title":"Redundant pairs on the invoice","scenario":"Your work description reads: \"Completely removed and disposed of each and every section of old galvanized pipe, first and foremost in the basement area, and fully and totally replaced with new PEX piping.\" The office says customers find long descriptions fishy.","task":"Rewrite the description with every redundant pair collapsed.","tips":["'Each and every' = every. 'Fully and totally' = (nothing). 'First and foremost' = first.","'Removed and disposed of' can just be 'removed and hauled away' — keep pairs only when both words do work.","Shorter reads more honest, not less thorough."],"focus":["concision","precision"],"placeholder":"Removed all galvanized pipe in the basement and replaced with PEX. Old pipe hauled away."},
    {"id":"concise-constr-early-09","level":"early","profession":"construction","title":"The site sign","scenario":"You're making the sign for the wet-cure slab: nobody walks on it until Thursday. Your draft is three sentences of explanation. People walking past a sign read for one second, maybe two.","task":"Write the sign in the fewest words that still stop someone's foot.","tips":["Command first, in big letters: the reader decides in one second.","One consequence or date if it earns its space: OFF UNTIL THU.","Every extra word shrinks the letters that matter."],"focus":["concision","impact"]},
    {"id":"concise-constr-early-10","level":"early","profession":"construction","title":"The parts-pickup text","scenario":"Your draft to the helper: \"When you get a chance later this morning, if you're passing anywhere near the supply house anyway, I was thinking it might make sense for you to maybe swing by and pick up the fittings that should be ready.\" It's one errand.","task":"Cut it to one clear sentence.","tips":["Who, what, where, when — everything else is padding.","'If you're passing anyway' invites it not to happen; ask for what you need.","Add the order number so one sentence is truly enough."],"focus":["concision","clarity"],"placeholder":"Grab the fittings at Emco this morning — order 4471, under the company name."},
    {"id":"concise-constr-early-11","level":"early","profession":"construction","title":"The whiteboard update","scenario":"The site trailer whiteboard has a lane for each trade. Yours has to fit in one line what your crew is doing this week and the one thing you're waiting on. Last week someone wrote a paragraph and the super photographed only the top half.","task":"Write your whiteboard line: this week's work plus your one dependency, max 12 words.","tips":["Telegraph style is legal on a whiteboard: drop articles, keep facts.","One dependency only — the one that actually stops you.","If it doesn't fit the lane, it isn't distilled yet."],"focus":["concision","structure"]},
    {"id":"concise-constr-early-12","level":"early","profession":"construction","title":"The padded estimate email","scenario":"Your estimate email to a homeowner runs 300 words: how much you'd love to help, your company's history, the weather window, and finally the number. Your boss forwarded you a competitor's version: five lines, and it won the job.","task":"Rewrite the estimate email at a third the length.","tips":["Number, scope, timeline, next step — four moves, four short lines each or less.","Enthusiasm is one sentence, not three.","The customer compares numbers; make yours the easiest to find."],"focus":["concision","audience"],"placeholder":"Thanks for having me out. Fence repair as discussed: $1,240 including materials."},
    {"id":"concise-constr-early-13","level":"early","profession":"construction","title":"The over-explained apology","scenario":"You forgot to bring the special-order faucet and the customer waited home for you. Your apology draft is nine sentences of the whole morning's chaos. Over-explaining a mistake makes it about you, not the fix.","task":"Write the apology in 3 sentences: sorry, the fix, the when.","tips":["One sentence of sorry, without a story attached.","Two sentences of fix: faucet in hand tomorrow, first stop, 8 a.m.","The excuse tour makes it worse; the specific fix makes it better."],"focus":["concision","impact"],"placeholder":"I'm sorry — I left your faucet at the shop and wasted your morning. Tomorrow you're my first stop at 8."},
    {"id":"concise-constr-early-14","level":"early","profession":"construction","title":"The crew group text","scenario":"You're texting the crew about tomorrow: new site, 6:30 start, park behind the fence, bring fall harnesses. Your draft opens with two lines about how today went. Half the crew reads texts standing in line at the gas station.","task":"Cut it so the four facts survive a five-second read.","tips":["Four facts, four fragments — no intro line.","Bold the change from routine: the 6:30 start is the trap.","Today's recap belongs in a different message or nowhere."],"focus":["concision","clarity"],"placeholder":"Tomorrow: Maple St site. 6:30 start. Park behind fence. Bring harnesses."},
    {"id":"concise-constr-early-15","level":"early","profession":"construction","title":"Instructions for the week away","scenario":"The homeowners leave tomorrow for a week while you finish the basement. Your draft note covers eleven points; four actually matter: lockbox code location, which switch stays on, the dog gate, your cell number. The rest is noise they'll skim past.","task":"Cut the note to the four essentials, one line each.","tips":["Sort must-know from nice-to-know, then delete nice-to-know.","One instruction per line — merged lines get half-followed.","Put your number last and alone so it's findable in a panic."],"focus":["concision","structure"]},
    {"id":"concise-constr-early-16","level":"early","profession":"construction","title":"The invoice line that says it","scenario":"The office bounced back your work order: the description field says \"Performed various plumbing repairs and associated works as required throughout the property as per discussion.\" The customer disputed it — because it says nothing.","task":"Rewrite as 1-2 lines that say exactly what was done, no filler.","tips":["'Various', 'associated works', 'as required' — these words hide the work; name it instead.","Specific and short beat long and vague: fixture, location, action.","A good description ends billing arguments before they start."],"focus":["concision","precision"],"placeholder":"Replaced kitchen faucet cartridge; cleared bathroom sink drain; resealed toilet base."},
    {"id":"concise-constr-early-17","level":"early","profession":"construction","title":"Say it clean, out loud","scenario":"Recorded at yesterday's huddle, your update was: \"So basically we're kind of, you know, pretty much done with the framing part of things, I guess the next thing would probably be starting on, like, the sheathing.\" The content was fine. The filler buried it.","task":"Say the same update aloud with zero filler words — record yourself once.","tips":["Slower beats filler: a pause is stronger than 'you know'.","Decide the sentence before you start it — filler is the sound of deciding mid-air.","Two sentences, then stop. Stopping is allowed."],"focus":["concision","clarity"]},
    {"id":"concise-constr-early-18","level":"early","profession":"construction","title":"The safety observation, shortened","scenario":"The near-miss card you drafted runs a full page: the extension cord across the stairwell, who might have tripped, your feelings about cords generally. Safety cards get read in a weekly stack of thirty — long ones get skimmed, which defeats the point.","task":"Cut the observation to 3 lines: what, where, fix.","tips":["What and where in line one, concrete: cord across stairwell B, second floor.","The fix you did or propose in line two: rerouted overhead.","Your feelings about cords don't make the card safer."],"focus":["concision","impact"],"placeholder":"Extension cord ran across stairwell B landing — trip hazard on the main route down."},
    {"id":"concise-constr-early-19","level":"early","profession":"construction","title":"Asking to leave early, minus the essay","scenario":"You need to leave at 3 for a dentist appointment. Your draft text to the foreman is seven sentences of apology, backstory, and promises. It's a routine request drowning in guilt.","task":"Cut it to 2 sentences: the ask and the coverage plan.","tips":["The ask with the time, then how your work is covered — done.","Routine requests deserve routine length.","Over-apologizing signals it's a bigger deal than it is."],"focus":["concision","clarity"],"placeholder":"Dentist at 3:30 — OK if I head out at 3? Conduit run will be done and I'll stage Friday's material first."},
    {"id":"concise-constr-early-20","level":"early","profession":"construction","title":"The meeting that could be a text","scenario":"You typed: \"Do you have some time in the next couple of days to maybe sit down and go over a few things about the Peterson job when it's convenient?\" The foreman will either ignore it or worry. You need ten minutes about one topic: the tile allowance.","task":"Rewrite the request naming topic, length, and a proposed time.","tips":["Vague meeting requests read as either nothing or trouble — name the topic.","Ten minutes and a proposed slot make yes easy.","If it's really one question, skip the meeting and ask it."],"focus":["concision","precision"]},
    {"id":"concise-constr-early-21","level":"early","profession":"construction","title":"The callback report, trimmed","scenario":"Your warranty-callback note for the office file: 200 words retelling the customer's version, your drive over, and the weather, wrapped around the one fact that matters — the duct joint had separated, you resealed it, twenty minutes.","task":"Rewrite the file note in 2 sentences.","tips":["File notes are for the next tech and billing: finding and fix, nothing else.","Cut the customer's retelling — the finding already says it.","Add the one forward-looking line only if true: no further issues expected."],"focus":["concision","precision"],"placeholder":"Found supply duct joint separated above laundry; resealed and strapped. 20 min, no parts."},
    {"id":"concise-constr-early-22","level":"early","profession":"construction","title":"The return request","scenario":"You're returning six unused sheets of drywall to the supplier. Your email draft explains the whole project's history before asking for credit. The returns desk needs: order number, items, condition, pickup or drop-off.","task":"Write the return request in 3 lines.","tips":["Write to the form the returns desk fills in: order, items, condition.","Project history doesn't speed up a credit.","End with the one question: pickup or should we drop off?"],"focus":["concision","clarity"]},
    {"id":"concise-constr-early-23","level":"early","profession":"construction","title":"The 30-second shift handoff","scenario":"The evening crew's lead just arrived and you have 30 seconds while packing up. Everything from your ten-hour day is pushing to come out. He needs: where you stopped, the one hazard, the one thing not to touch.","task":"Say the handoff aloud in 3 sentences.","tips":["Rank ruthlessly: stopping point, hazard, don't-touch — nothing else makes the cut.","Physical pointers beat descriptions: 'that wall', 'this valve' while pointing.","Ask one closing question: what do you need from me before I go?"],"focus":["concision","structure"],"placeholder":"We stopped mid-run on the north wall — wire's pulled but nothing's terminated."},
    {"id":"concise-constr-early-24","level":"early","profession":"construction","title":"What you did today, doorway version","scenario":"The homeowner asks 'how'd it go today?' as you load the van. You have a full day to report and she wants a sentence, maybe two. The long version makes her regret asking; the right version builds trust daily.","task":"Answer in 2 sentences: what got done and what happens tomorrow.","tips":["One sentence back, one forward — that's the whole formula.","Name something she can see: the upstairs bath has its new tub.","Save the详 details for the weekly summary or her actual questions."],"focus":["concision","audience"],"placeholder":"Good day — the new tub's in and connected upstairs. Tomorrow we tile around it."},
    {"id":"concise-constr-early-25","level":"early","profession":"construction","title":"The defensive reply, disarmed","scenario":"The site super emailed that your crew left the corridor blocked yesterday, copying the foreman. Your draft reply is four paragraphs re-arguing the whole day. It was true for one hour during a delivery, and it's already fixed.","task":"Cut the reply to 2 sentences that close the issue.","tips":["Long defenses read as guilt; short facts read as done.","Acknowledge the true part, state the fix, stop typing.","Skip re-litigating the hour-by-hour; nobody's reading it."],"focus":["concision","impact"],"placeholder":"Fair flag — the corridor was blocked for about an hour during our delivery. Material's staged inside now and it won't repeat."}
  ],
  "precision-and-evidence": [
    {"id":"precision-constr-early-01","level":"early","profession":"construction","title":"'A bunch of shingles' orders nothing","scenario":"The foreman asks what you need to finish the garage roof and you say \"a bunch more shingles and some nails.\" He can't order 'a bunch' — the supplier sells bundles, and a wrong guess means a second delivery charge or a stalled roof.","task":"Rewrite the request with exact quantities and how you counted.","tips":["Measure and do the math: squares left, times three bundles, plus waste.","Say how you got the number so he can trust it: I measured the remaining slope.","'Some nails' becomes a box count and a type."],"focus":["precision","clarity"],"placeholder":"Need 9 more bundles of the same shingle and one box of 1-1/4\" coil nails — that's the last 3 squares plus 10% waste."},
    {"id":"precision-constr-early-02","level":"early","profession":"construction","title":"How out of level is it?","scenario":"You tell the foreman the old kitchen floor \"isn't very level.\" Whether the cabinet install proceeds, gets shimmed, or needs self-leveler depends entirely on how much — and 'not very' could mean anything.","task":"Rewrite the report with a measurement, over what distance, and where the low spot is.","tips":["Numbers, not adjectives: 3/4 inch over 8 feet.","Say where: dropping toward the exterior wall.","The measurement decides the fix — that's why it's the message."],"focus":["precision","impact"],"placeholder":"Floor drops 3/4\" over 8 feet, low at the exterior wall — shims won't cover that on the long run."},
    {"id":"precision-constr-early-03","level":"early","profession":"construction","title":"'Soon' is not a delivery date","scenario":"The homeowner asks when her vanity arrives and you say \"soon, should be pretty quick.\" She's booking time off work to be home for it. 'Soon' forces her to guess and call the office twice.","task":"Rewrite the answer with a specific day and whether it's confirmed or estimated.","tips":["Give the day the supplier actually gave you.","Label your confidence: confirmed, or estimated and I'll verify.","If you don't know, say when you WILL know."],"focus":["precision","audience"],"placeholder":"Supplier says Thursday — that's their estimate, not confirmed. I'll have a confirmed date by tomorrow noon."},
    {"id":"precision-constr-early-04","level":"early","profession":"construction","title":"The crack in the foundation","scenario":"You spotted a crack in the basement foundation and your text says \"there's a pretty big crack down here, looks bad.\" Whether this is a monitor-it hairline or a call-the-engineer problem lives in details you didn't give.","task":"Rewrite the report with width, length, direction, and location.","tips":["Width in fractions of an inch — hold a tape to it.","Direction matters: vertical, diagonal from a corner, horizontal.","Add the photo, but the words should stand alone."],"focus":["precision","clarity"],"placeholder":"Horizontal crack in the north foundation wall, about 1/8\" wide and 4 feet long, 2 feet below grade line — photo attached."},
    {"id":"precision-constr-early-05","level":"early","profession":"construction","title":"What, so what, now what","scenario":"Your moisture meter reads 16% on the subfloor where hardwood goes in Monday. You text the foreman just the number. He's not a flooring guy — the number alone leaves him asking 'and?'","task":"Write a 3-sentence update: the reading, why it matters, what you recommend.","tips":["What: subfloor is at 16%.","So what: hardwood needs 12% or less, or boards cup after install.","Now what: run heat and fans over the weekend, retest Monday at 7."],"focus":["precision","structure"],"placeholder":"Subfloor is reading 16% moisture. Hardwood needs 12% or under or it cups. Recommend heat and fans all weekend, retest Monday before we start."},
    {"id":"precision-constr-early-06","level":"early","profession":"construction","title":"The skeptic's 'says who?'","scenario":"You tell the foreman the new self-drilling anchors are \"way faster\" than drilling and tapping. He's heard 'way faster' about every gadget in the catalog. He'll ask: faster by how much, measured how?","task":"Rewrite the claim so it survives a skeptic — with a measured comparison.","tips":["Time both methods yourself before you claim anything.","Give both numbers: old way, new way, over how many anchors.","One honest measurement beats three enthusiastic adjectives."],"focus":["precision","impact"],"placeholder":"I timed it: 12 anchors the old way took 40 minutes, the self-drillers did 12 in 14. That's an hour saved per unit."},
    {"id":"precision-constr-early-07","level":"early","profession":"construction","title":"'They're always late' won't fly","scenario":"You want the foreman to lean on the drywall crew, so you say \"they're always showing up late.\" 'Always' is an argument-starter — the drywall lead will name the one day he was early and the complaint dies.","task":"Rewrite the complaint as counted fact: how many times, out of how many, this period.","tips":["Count from your daily logs: late 4 of the last 6 mornings.","Say by how much: 45 minutes to an hour each time.","State the cost: my crew stood down waiting both Tuesdays."],"focus":["precision","impact"],"placeholder":"Drywall crew has been 45+ minutes late 4 of the last 6 mornings — my guys lost about 3 hours waiting on them this week."},
    {"id":"precision-constr-early-08","level":"early","profession":"construction","title":"The leak, quantified","scenario":"Your service note says the customer's supply line \"leaks quite a bit.\" The office has to decide between booking a one-hour fix or a half-day repipe, and 'quite a bit' books nothing.","task":"Rewrite the note with rate, location, and what it's reaching.","tips":["Rate: a drip per second, a steady stream, cup per hour.","Exact location: compression joint under the kitchen sink, hot side.","What's at risk: cabinet floor is already swelling."],"focus":["precision","concision"],"placeholder":"Hot supply compression joint under kitchen sink leaking about a cup an hour — cabinet floor swelling. One-hour fix if booked this week."},
    {"id":"precision-constr-early-09","level":"early","profession":"construction","title":"Proof the fix held","scenario":"You repaired the gas line and want to tell the foreman it's good. \"Tested fine, no issues\" is what everyone says right before a callback. The record that protects you is the actual test numbers.","task":"Write the completion note with the test method, numbers, and duration.","tips":["Name the test: pressure test at 15 psi.","Give the result over time: held 15 psi for 30 minutes, no drop.","Numbers in the file end arguments a year later."],"focus":["precision","impact"],"placeholder":"Gas line repair complete — pressure tested at 15 psi, held 30 minutes with zero drop. Photos of the gauge in the job file."},
    {"id":"precision-constr-early-10","level":"early","profession":"construction","title":"How full is the panel?","scenario":"The homeowner is deciding on the hot tub circuit and asks if her panel can take it. You say \"it's getting pretty full in there.\" She hears a maybe. The panel is a countable object.","task":"Answer with the exact count: slots total, slots used, what's left.","tips":["Count, don't estimate: 24 spaces, 22 used.","Translate to her question: the hot tub needs 2 — it fits, but it's the last one.","Precision here reads as competence; vagueness reads as upsell."],"focus":["precision","audience"],"placeholder":"Your panel has 24 spaces and 22 are used. The hot tub takes the last 2 — it fits, but anything after this needs a subpanel."},
    {"id":"precision-constr-early-11","level":"early","profession":"construction","title":"'A couple hours' becomes an argument","scenario":"You told the homeowner the repair would take \"a couple of hours\" — it took five, and now she's disputing the bill. The estimate wasn't dishonest, just unanchored. Next time the number needs a basis and a range.","task":"Write the time estimate you SHOULD have given, with range and what could move it.","tips":["Give a range with the reason: 2 hours if the valve comes free, up to 5 if it's seized.","Name the checkpoint: I'll know which within 30 minutes of opening it.","A conditional estimate is honest; a hopeful one is a future argument."],"focus":["precision","clarity"],"placeholder":"Best case 2 hours if the old valve comes out clean; if it's seized like they often are in these houses, up to 5. I'll know within the first half hour."},
    {"id":"precision-constr-early-12","level":"early","profession":"construction","title":"Calling up measurements","scenario":"You're on the ground cutting; your partner is up top calling measurements. He yells \"a little over thirty-six and a half.\" You cut, climb, and it's short. 'A little over' cost a board.","task":"Say (or write) the measurement call the way it should sound — and the readback you'd give.","tips":["Sixteenths, not vibes: thirty-six and nine sixteenths.","Read it back before cutting — the echo catches the error.","Agree the convention: are we calling to the mark or to the cut side?"],"focus":["precision","concision"]},
    {"id":"precision-constr-early-13","level":"early","profession":"construction","title":"The change order needs measured footage","scenario":"The homeowner added a fence run and your note to the office says \"add the extra fence to the quote — it's a fair bit more.\" The office can't price 'a fair bit.' You have a tape measure and the yard is right there.","task":"Write the change note with measured quantities the office can price directly.","tips":["Measure the run and count what it drives: 42 feet, 6 more posts, 5 panels.","Include what changes and what doesn't: same gate count, same height.","Priceable notes get quoted same-day; vague ones sit in the inbox."],"focus":["precision","concision"],"placeholder":"Change for the Patels: add 42 linear feet along the east line — 6 posts, 5 panels, same 6' height, no new gates."},
    {"id":"precision-constr-early-14","level":"early","profession":"construction","title":"Old wiring, specified","scenario":"Your report says the attic has \"really old, sketchy wiring.\" The office needs to quote a remediation, and the insurance question behind it is specific: what type, how much, where.","task":"Rewrite the finding with type, extent, and locations.","tips":["Name what you saw: cloth-insulated two-wire, no ground, brittle at every junction.","Extent: roughly how many circuits or rooms it feeds.","'Sketchy' is a feeling; 'no ground and brittle insulation' is a finding."],"focus":["precision","clarity"],"placeholder":"Attic has cloth-insulated 2-wire cable, no ground, feeding the three upstairs bedrooms — insulation crumbles at every box I opened."},
    {"id":"precision-constr-early-15","level":"early","profession":"construction","title":"The callback pattern in the pile","scenario":"Flipping through the service tickets, you notice something: five of the last seven faucet callbacks are the same brand of cartridge, all installed in the past year. Sent as seven ticket summaries, nobody sees it. The insight is the message.","task":"Write a 2-sentence note to the office that states the pattern, not the raw tickets.","tips":["Lead with the cluster: 5 of 7 recent faucet callbacks are the same cartridge.","Add the actionable read: stop installing that model, or buy from a different batch.","Data plus meaning — don't make the office do the analysis."],"focus":["precision","impact"],"placeholder":"5 of our last 7 faucet callbacks are the same Delaro cartridge, all installed within a year. Worth switching brands before the rest come back."},
    {"id":"precision-constr-early-16","level":"early","profession":"construction","title":"'Behind schedule' — by how much?","scenario":"At the site meeting you say your trade is \"running a bit behind.\" The super pushes: how far behind, on what, and does it move his drywall date? 'A bit' answers none of it.","task":"Give the schedule status aloud in 2-3 sentences with days, tasks, and the downstream impact.","tips":["Quantify: two days behind, all of it in the ensuite rough-in.","Name what it hits: drywall can still start Monday everywhere except that one room.","A precise 'behind' keeps trust; a vague one spreads worry."],"focus":["precision","structure"],"placeholder":"We're two days behind, all of it in the ensuite. Drywall can start Monday as planned everywhere except that room — it's ready Wednesday."},
    {"id":"precision-constr-early-17","level":"early","profession":"construction","title":"Photograph it before the wall closes","scenario":"You're about to close the wall over your neat plumbing rough-in. Six months from now, if a screw finds a pipe, the only evidence of where your lines ran is what you record today. \"Took some pics\" isn't a record.","task":"Write the photo-log entry that turns today's pictures into usable evidence.","tips":["Each caption: room, wall, what's shown, distance references — 'supply lines 14 inches left of window frame'.","Date and job name on the entry, not just in your camera roll.","Write it for a stranger with a lawsuit, not for yourself next week."],"focus":["precision","structure"],"placeholder":"Main bath, north wall, pre-drywall 06/12: supply lines rise 14\" left of window frame, drain crosses at 22\" height — 4 photos, wide plus close."},
    {"id":"precision-constr-early-18","level":"early","profession":"construction","title":"The scaffold complaint that gets fixed","scenario":"You told the foreman the scaffold on the east wall \"doesn't feel safe.\" He walked over, bounced on it, shrugged. Feelings are dismissible. What you actually saw is not: missing pins, no toe boards on one level, a base plate on soil.","task":"Rewrite the concern as a list of specific, checkable deficiencies.","tips":["Name components: two missing locking pins on the second lift, no toe boards on level 3.","Location for each — which bay, which level.","A checkable list forces a check; 'feels off' invites a shrug."],"focus":["precision","impact"],"placeholder":"East scaffold, three specifics: locking pins missing on two frames second lift, no toe boards on level 3, and the northeast base plate is sitting on soil, not the mudsill."},
    {"id":"precision-constr-early-19","level":"early","profession":"construction","title":"Which door, where it rubs","scenario":"Your punch-list entry says \"bedroom door sticks.\" The carpenter doing punch work will open four bedroom doors, find them all roughly fine, and mark it complete. The item needed an address and a symptom.","task":"Rewrite the punch item so someone else can find and fix it without you.","tips":["Which room, which door: northeast bedroom, closet door.","Where it rubs: top corner, latch side — you can see the shine mark.","When: only when it's humid, or always? Say so."],"focus":["precision","clarity"],"placeholder":"NE bedroom closet door rubs at the top latch-side corner — visible shine mark on the jamb. Rubs every time, not humidity."},
    {"id":"precision-constr-early-20","level":"early","profession":"construction","title":"The smell of gas, pinned down","scenario":"A tenant reports she \"smells gas sometimes, somewhere near the kitchen.\" You investigated: your detector reads at the stove's flex connector, only when the oven runs. Your report back can't be as vague as the complaint was.","task":"Write the finding with location, condition, and the reading.","tips":["Pin it: flex connector behind the range, detector reads only when the oven is on.","Say what you ruled out: meter and main line read clean.","The precision is what makes 'fixed it' credible later."],"focus":["precision","clarity"],"placeholder":"Traced it: small leak at the range flex connector, detector picks it up only when the oven runs. Meter and main line read clean. Replacing the connector today."},
    {"id":"precision-constr-early-21","level":"early","profession":"construction","title":"Extra work, itemized","scenario":"Your invoice note for the extra work says \"additional time and materials for unforeseen issues — 1 day.\" The homeowner is disputing it. She'd pay for what she can see; she won't pay for a fog.","task":"Rewrite the extra-work description itemized: what, why, hours, materials.","tips":["Each item: found X, did Y, hours and materials attached.","Tie each to the moment she knew: 'the rot we showed you Tuesday'.","Itemized reads honest; lumped reads padded — same total."],"focus":["precision","audience"],"placeholder":"Extras: (1) replaced 3 rotted studs behind tub — shown to you Tues — 4 hrs + lumber $85; (2) rerouted vent hitting new fan housing, 2 hrs + fittings $40."},
    {"id":"precision-constr-early-22","level":"early","profession":"construction","title":"Concrete weather call, with numbers","scenario":"You're the one on site at 6 a.m. and the pour decision is yours to inform. \"It's pretty cold but probably fine\" transfers nothing. You have a thermometer, a forecast, and the spec sheet in the trailer.","task":"Write the 6 a.m. text with the readings and the spec limit side by side.","tips":["Report measurements: air temp now, overnight low forecast, ground temp.","Put the spec next to them: mix needs 5°C and rising.","Recommend, but let the numbers do the arguing."],"focus":["precision","impact"],"placeholder":"6am readings: air 3°C, ground 2°C, forecast high 9 by noon, tonight -4. Spec wants 5 and rising at pour. Recommend pushing to 10:30 start with blankets for tonight."},
    {"id":"precision-constr-early-23","level":"early","profession":"construction","title":"'Should be enough' material","scenario":"The foreman asks if there's enough tile for the bathroom and you eyeball the stack: \"should be enough.\" If you're wrong, it's a dye-lot mismatch and a two-week reorder. This is a counting problem pretending to be a judgment call.","task":"Write the answer you'd give after actually counting: coverage math shown.","tips":["Do the math out loud: 88 sq ft of wall, 6 boxes at 15.5 sq ft is 93.","Name the margin: 5 feet spare is under the 10% cuts usually eat.","Recommend off the math: order one more box today, same dye lot."],"focus":["precision","structure"],"placeholder":"Counted it: walls need 88 sq ft, we have 6 boxes = 93. That's 5% spare and cuts usually eat 10 — order one more box today while the dye lot's still in stock."},
    {"id":"precision-constr-early-24","level":"early","profession":"construction","title":"The torque record that saves you","scenario":"A year from now, if that deck railing fails, the question will be whether the ledger was fastened to spec. Your log entry today — \"installed railing per plans\" — proves nothing. The evidence habit starts now.","task":"Write the completion entry with the spec-relevant specifics recorded.","tips":["Record what the spec asked and what you did: fastener type, size, spacing, count.","Note the verification: every lag hit solid framing, checked with the detector.","Write it like it'll be read aloud in a dispute — because that's exactly when it gets read."],"focus":["precision","impact"],"placeholder":"Deck railing installed: posts lagged with 1/2\" x 6\" structural screws, 2 per post into rim joist, all 8 posts confirmed into solid framing. Per drawing D-3."},
    {"id":"precision-constr-early-25","level":"early","profession":"construction","title":"Estimate versus measurement, labeled","scenario":"The foreman asks how much conduit is left on site. You can see two partial rolls. You say \"maybe 200 feet\" in the same voice you'd report a measured count — and he orders based on it.","task":"Give the answer twice: once as the labeled estimate, then as you would after measuring.","tips":["Label the guess as a guess: 'eyeballing it, 150-250 — want me to measure?'","Offer the upgrade: two minutes with a tape turns it into a number.","Never let an estimate wear a measurement's clothes."],"focus":["precision","clarity"],"placeholder":"Eyeballing the rolls, somewhere between 150 and 250 feet — give me two minutes and I'll get you a real number."}
  ],
  "executive-presence": [
    {"id":"presence-constr-early-01","level":"early","profession":"construction","title":"'Whatever you think' isn't an answer","scenario":"The foreman asks whether the subpanel should go on the left or back garage wall. You've measured both, and left is clearly better — shorter runs, clear of the future workbench. You hear yourself say \"either works, whatever you think.\"","task":"Rewrite the answer to own a recommendation with the reason attached.","tips":["State your pick first: left wall.","One or two reasons, concrete: shorter home runs, clears the bench area.","You did the thinking — the neutral shrug throws it away."],"focus":["impact","clarity"],"placeholder":"Left wall. Runs are 15 feet shorter and it stays clear of where he wants the workbench."},
    {"id":"presence-constr-early-02","level":"early","profession":"construction","title":"Kill the pre-apology","scenario":"You have a genuinely good idea about staging material closer to the hoist, but at the huddle you open with \"this is probably stupid, but...\" The crew hears 'stupid' and half-listens to the rest. Your framing sank your idea before it launched.","task":"Say the suggestion aloud with the pre-apology cut and the idea stated straight.","tips":["Delete 'probably stupid', 'just a thought', 'I don't know but'.","Open with the idea itself: 'We'd save trips if the brick staged next to the hoist.'","If it needs a softener, use a question at the END: 'worth trying?'"],"focus":["impact","concision"]},
    {"id":"presence-constr-early-03","level":"early","profession":"construction","title":"Signpost the huddle update","scenario":"You have three things for the morning huddle: yesterday's inspection result, today's plan, and a materials problem. You usually launch into the middle of it and watch the foreman's eyes drift, unsure how long you'll go.","task":"Deliver the update aloud, opening with a signpost, then the three points in order.","tips":["Map first: 'Three things — inspection, today, and one problem.'","Then walk the map in that exact order.","The signpost tells people how to listen; that alone reads as command."],"focus":["structure","impact"],"placeholder":"Three things: inspection passed, today's plan, and one materials problem I need help on."},
    {"id":"presence-constr-early-04","level":"early","profession":"construction","title":"Talking to the inspector","scenario":"The electrical inspector points at your junction box and asks why the splice is there. It's legitimate — an approved layout change — but nerves make you over-talk: three explanations, an apology, and a story about the framer. Over-explaining reads as guilt.","task":"Say the answer as you should: direct, factual, one sentence, then stop.","tips":["Answer the actual question: 'Layout changed after the walkthrough — that box stays accessible behind a panel.'","Then stop talking. Silence after a clean answer is confidence.","Have the paperwork ready instead of narrating it."],"focus":["concision","impact"]},
    {"id":"presence-constr-early-05","level":"early","profession":"construction","title":"Fact and opinion, untangled","scenario":"Your report on the framing you found: \"whoever framed this bathroom was clearly rushing and didn't care, the layout is basically wrong.\" The foreman needs what you observed, separated from what you concluded — especially since the framer is his cousin.","task":"Rewrite in two labeled parts: what you measured/saw, then your read on it.","tips":["Facts first, neutral: king stud is 1/2\" out of plumb, window RO is 1\" narrow.","Then judgment, marked as yours: 'my read: it needs reframing, not shimming.'","Untangled facts survive the messenger getting challenged."],"focus":["precision","impact"],"placeholder":"What I found: window RO is 1\" narrower than the plan and the king stud is 1/2\" out of plumb. My read: shims won't save it — that opening needs reframing."},
    {"id":"presence-constr-early-06","level":"early","profession":"construction","title":"Say the number like you mean it","scenario":"Recorded on site, your measurement calls sound like questions: \"forty-two and a quarter?\" Every call floats upward, asking permission. Your partner has started double-checking everything you call — the tone taught him to.","task":"Practice aloud: call five measurements as statements, flat and final.","tips":["End the number going DOWN in pitch, not up.","Same words, different music — the drop is the authority.","If you're actually unsure, say 'check me on this' — don't smuggle doubt into the tone."],"focus":["clarity","impact"]},
    {"id":"presence-constr-early-07","level":"early","profession":"construction","title":"Disagreeing with the journeyman","scenario":"The journeyman tells you to run the cable under the joists. You're almost sure the plan calls for it through the web holes — you read it this morning. He's been doing this twenty years and you've been doing it twenty weeks. Silence is easy and wrong.","task":"Say the pushback aloud: respectful, specific, anchored to the document.","tips":["Anchor to the source, not your opinion: 'the drawing shows it through the webs — want me to grab it?'","Ask as a check, not a challenge — but do ask.","Being junior means you cite evidence, not that you swallow it."],"focus":["clarity","audience"],"placeholder":"Quick check before I pull this — the drawing this morning showed these through the web holes. Want me to bring it over?"},
    {"id":"presence-constr-early-08","level":"early","profession":"construction","title":"Owning the miscut","scenario":"You miscut the last piece of the expensive stair tread stock. The foreman's going to find out either way. Groveling makes it about your feelings; deflecting makes it worse. There's a steady middle: state it, own it, bring the fix.","task":"Write the message: mistake stated plainly, cause in one line, your fix proposed.","tips":["No cushioning, no drama: 'I miscut the last tread — my mistake, read the wrong side of the line.'","One-line fix with cost: supplier has stock, $60, I'll cover the pickup at lunch.","Steady ownership builds more trust than never erring."],"focus":["clarity","impact"],"placeholder":"I miscut the last stair tread — my fault, measured to the wrong side of my mark. Supplier has the stock, about $60. I can pick it up at lunch so we don't lose the day."},
    {"id":"presence-constr-early-09","level":"early","profession":"construction","title":"The tool request with a spine","scenario":"The crew needs a second impact driver — you lose twenty minutes a day sharing one. Your draft to the foreman: \"if there's ever any budget, it might be nice to maybe have another impact at some point.\" That sentence was designed to be ignored.","task":"Rewrite as a direct, costed request with the payback stated.","tips":["Ask for the thing: 'we need a second impact on this crew.'","Cost against loss: $180 tool versus 20 minutes a day of waiting.","End with a proposed action: OK to grab one on the account this week?"],"focus":["impact","concision"],"placeholder":"We need a second impact — sharing one costs us about 20 minutes a day. It's $180. OK if I grab one on the account this week?"},
    {"id":"presence-constr-early-10","level":"early","profession":"construction","title":"Calibrated words for a diagnosis","scenario":"The furnace won't stay lit and the homeowner asks what's wrong. You THINK it's the flame sensor — 80% — but you hear yourself say \"it's definitely the flame sensor.\" If you're wrong, 'definitely' costs you the customer's trust on everything after.","task":"Say the diagnosis with calibrated confidence: what's likely, what would confirm it.","tips":["Match words to certainty: 'most likely', 'nine times out of ten', not 'definitely'.","Give the confirm step: I'll clean it, and we'll know in ten minutes.","Calibration isn't hedging — it's precision about what you know."],"focus":["precision","audience"],"placeholder":"Most likely the flame sensor — that's the cause nine times out of ten with these symptoms. I'll clean it now and we'll know within ten minutes."},
    {"id":"presence-constr-early-11","level":"early","profession":"construction","title":"Your first site meeting slot","scenario":"The foreman is off site and told you to give your trade's status at the Tuesday coordination meeting — GC, super, three other trade leads at the plan table. You get ninety seconds. Mumbling through it costs your whole crew credibility.","task":"Write the 90-second status you'd deliver: schedule answer first, then the two things others need from you.","tips":["Lead with what the room cares about: on track for Friday, or not.","Name your asks by trade: 'need the framers done in unit 3 by Wednesday noon.'","Slow, loud enough, and done early beats fast and complete."],"focus":["structure","audience"],"placeholder":"Electrical is on track for Friday's cover inspection. Two things I need: framers clear of unit 3 by Wednesday noon, and a decision on the lobby fixture by Thursday."},
    {"id":"presence-constr-early-12","level":"early","profession":"construction","title":"No to the shortcut, steady","scenario":"A senior guy on the crew tells you to skip the lockout and just be quick — \"it's a two-minute job, breaker's right there.\" Everyone's watching how the new kid handles it. You need a no that's firm without being a scene.","task":"Say the refusal aloud: calm, short, no lecture, no apology.","tips":["A quiet no with a reason beats a speech: 'I lock out everything live. Takes me ninety seconds.'","Don't ask permission to be safe, and don't sermonize either.","Offer the workaround, not the argument: 'time me.'"],"focus":["impact","concision"]},
    {"id":"presence-constr-early-13","level":"early","profession":"construction","title":"Sure, likely, or guessing — label it","scenario":"The foreman asks three questions in a row: is the rough-in done (yes, certain), will parts land Thursday (probably), and how long is the trim work (honestly guessing). You answer all three in the same confident tone — and the guess sounds like the certainty.","task":"Answer all three aloud, labeling the confidence of each differently.","tips":["'Done and tested' vs 'supplier says Thursday, I'd call it 80%' vs 'rough guess: two days — I'll firm it up tomorrow.'","The labels are what let him plan — uniform confidence is noise.","Being caught guessing in a certainty voice costs all your future certainties."],"focus":["precision","clarity"],"placeholder":"Rough-in: done and tested. Parts: supplier says Thursday — I'd call that 80%. Trim: honest guess is two days, I'll have a real number after tomorrow morning."},
    {"id":"presence-constr-early-14","level":"early","profession":"construction","title":"'How old are you, anyway?'","scenario":"The homeowner watches you set up and asks, half-joking, \"shouldn't there be an adult doing this?\" You're 22 and licensed for exactly this work. Defensiveness confirms her worry; a joke at your own expense feeds it.","task":"Say the response: unruffled, factual, and back to work.","tips":["Answer the real question — competence — not the age jab: 'I'm licensed for this, and the company checks my work on every job.'","Light is fine, self-deprecating is not.","Then pivot to the work: here's what I'm doing first."],"focus":["audience","impact"],"placeholder":"Ha — I get that a lot. I'm fully licensed for this work and my foreman signs off on every job. First thing I'm doing is..."},
    {"id":"presence-constr-early-15","level":"early","profession":"construction","title":"The recommendation buried at the bottom","scenario":"Your message about the failing sump pump walks through the inspection, the readings, the options, and finally — line nine — 'so I'd probably replace it.' The foreman read three lines and moved on. Your recommendation never got read.","task":"Rewrite with the recommendation as the first sentence and the support after.","tips":["Verdict first: 'Replace the sump pump this week.'","Then the two strongest reasons, then the detail.","If they only read one line, make it the line that decides."],"focus":["structure","impact"],"placeholder":"Recommend replacing the Hartley sump pump this week. It's drawing double rated amps and seized twice during yesterday's test —"},
    {"id":"presence-constr-early-16","level":"early","profession":"construction","title":"Finishing your sentence","scenario":"At the huddle, you're halfway through flagging the delivery clash when a louder voice talks over you and the topic moves on. The clash is real: two trucks, one crane slot. Letting it drop means owning the chaos at 1 p.m.","task":"Say the re-entry line: polite, firm, and complete the point.","tips":["Claim the floor with a handle: 'Before we break — the delivery clash needs thirty seconds.'","Then deliver it compressed: two trucks, one crane, 1 p.m. — which one moves?","Re-raising once, calmly, is presence. Letting it die is not."],"focus":["impact","concision"],"placeholder":"Before we break — thirty seconds on a real problem: steel and glass are both booked for the crane at 1. Which one moves?"},
    {"id":"presence-constr-early-17","level":"early","profession":"construction","title":"Radio voice","scenario":"Your radio calls come out rushed and mumbled, and twice today someone keyed up with \"say again?\" On a site radio, presence is mostly pace and order: who, who, what, over. The words are simple; the delivery is the skill.","task":"Say three radio calls aloud — a lift request, a hazard flag, an all-clear — steady and once each.","tips":["Protocol order every time: who you're calling, who you are, the message.","Half your normal speed; the radio eats fast talk.","One breath, one message. If it needs two breaths, it's two calls."],"focus":["clarity","concision"]},
    {"id":"presence-constr-early-18","level":"early","profession":"construction","title":"Tested versus assumed, out loud","scenario":"The foreman asks if the circuits in the finished basement are all on the new panel. You verified the outlets; you assumed the lights. If you blend those into one confident 'yes', the assumption inherits credibility it didn't earn.","task":"Give the answer with tested and assumed clearly split.","tips":["Split the claim: 'Outlets, verified — I tested every one. Lights I haven't traced yet.'","Offer to close the gap: give me 20 minutes with the tester.","Presence isn't knowing everything; it's being exact about what you know."],"focus":["precision","clarity"],"placeholder":"Outlets: yes, verified — tested every one this morning. Lights I haven't traced yet. Give me 20 minutes and I'll confirm those too."},
    {"id":"presence-constr-early-19","level":"early","profession":"construction","title":"Make the decision easy to make","scenario":"You need the foreman to decide on the vent routing before drywall Monday, and he's slammed. Your draft dumps the whole problem in his lap. A decision-ready framing — two options, your pick, one question — gets answered from his truck.","task":"Rewrite the message so he can decide with a one-word reply.","tips":["Frame the choice: 'Option A through the joists (cleaner, half day more), Option B boxed soffit (faster, visible).'","State your pick and why in one line.","End with the yes/no: 'Going with A unless you say otherwise by Friday.'"],"focus":["structure","concision"],"placeholder":"Vent routing needs a call before Monday. A: through joists — cleaner, costs half a day. B: boxed soffit — faster, visible in the rec room. I'd go A. OK?"},
    {"id":"presence-constr-early-20","level":"early","profession":"construction","title":"'I guess I could' volunteers nothing","scenario":"The foreman asks who can handle the service call across town on Saturday morning. You can, and you want the hours and the trust. What comes out is \"I mean, I guess I could probably do it, if nobody else wants it.\"","task":"Say the volunteering line as a commitment, not a maybe.","tips":["Commit plainly: 'I'll take it. I've done two calls at that building.'","Add the one thing that makes you the right pick, not five.","Half-raised hands get half the credit and all the work anyway."],"focus":["impact","concision"]},
    {"id":"presence-constr-early-21","level":"early","profession":"construction","title":"Flagging your own fix to the inspector","scenario":"Before the plumbing inspector starts his walkthrough, you know he'll find the spot where you corrected a slope problem last week. You could hope he doesn't notice the rework marks — or you could name it first and own the story.","task":"Say the proactive flag: what was wrong, what you did, where to look.","tips":["Volunteer it before he finds it: 'One thing to show you — the main drain was under-sloped, we re-hung it Tuesday.'","Naming it first makes it your competence, not his discovery.","Have the specifics ready: measurement before, measurement after."],"focus":["impact","structure"],"placeholder":"Before you start — one thing worth showing you. The main drain read an eighth per foot where it needs a quarter, so we re-hung that run Tuesday. It's at a quarter now, happy to show you."},
    {"id":"presence-constr-early-22","level":"early","profession":"construction","title":"'Will it hold?' — say what you can stand behind","scenario":"You built temporary shoring for the beam replacement and the foreman asks, in front of the crew, \"that'll hold, right?\" It's sized off the chart with margin, but 'will hold' and 'should hold' are different promises, and everyone will work under your answer.","task":"Give the answer aloud: what you sized it for, your confidence, and the one condition.","tips":["Anchor the claim: sized off the chart for twice the load it's carrying.","State the condition that keeps it true: nobody moves the posts, and it gets checked after the crane pass.","A conditioned yes is stronger than a bare one — it shows you know where the risk lives."],"focus":["precision","impact"],"placeholder":"Yes — it's sized for twice what it's carrying, off the shoring chart. Two conditions: the posts don't move, and I re-check it after the crane pass."},
    {"id":"presence-constr-early-23","level":"early","profession":"construction","title":"The apology sandwich, opened","scenario":"Your request for Friday's material reads: \"Sorry to keep bugging you about this, I know you're busy, but if there's any chance the rebar could maybe come Thursday instead, that would be amazing, sorry again.\" Two apologies, one 'maybe', zero authority.","task":"Rewrite without the sandwich: the ask, the reason, the deadline.","tips":["One ask, stated: 'Can the rebar land Thursday instead of Friday?'","One reason: we pour Friday at 8 — Friday delivery means a crew standing around.","Zero apologies for doing your job."],"focus":["concision","impact"],"placeholder":"Can the rebar come Thursday instead of Friday? We pour Friday at 8, so a Friday drop leaves the crew waiting on steel."},
    {"id":"presence-constr-early-24","level":"early","profession":"construction","title":"Standing behind your count","scenario":"You counted the anchor bolts twice: 46, four short of the drawing. The foreman glances at the crate and says \"there's no way that's short, they always ship full.\" The easy move is 'maybe I miscounted.' You didn't.","task":"Say the response: hold your count, offer the re-verify, no folding and no bristling.","tips":["Restate the fact with its basis: 'I counted twice, laid them out in rows of ten — 46.'","Offer the check, not the retreat: 'count with me, takes two minutes.'","Folding on facts you verified teaches people your facts are soft."],"focus":["impact","precision"],"placeholder":"I counted twice and laid them in rows of ten — it's 46. Count with me if you want, two minutes. Either way we're four short of the drawing."},
    {"id":"presence-constr-early-25","level":"early","profession":"construction","title":"Own your dates in the trades meeting","scenario":"At coordination, the GC asks when your crew clears the second floor. The real answer is Wednesday, but the room's habit is padding and vagueness — 'probably mid-to-late next week sort of thing.' Vague dates get you scheduled around, not with.","task":"Say the commitment aloud: the date, the condition, and what you'll do if it slips.","tips":["Name the day: 'We're off the second floor Wednesday end of day.'","One condition if real: 'assuming the window package lands Monday like it's tracking.'","Add the insurance: 'if that slips, you'll hear from me Monday noon, not Wednesday.'"],"focus":["precision","audience"],"placeholder":"We're off the second floor Wednesday end of day, assuming the windows land Monday like they're tracking. If that slips you'll know from me Monday noon."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-constr-early-01","level":"early","profession":"construction","title":"The inspector's direct question","scenario":"The inspector points at the joist bay and asks: \"Why is there no nail plate on that line?\" Your instinct is to explain the whole morning — the helper, the schedule, the missing box of plates. He asked one question with a one-line answer.","task":"Say the answer: direct first sentence, then the fix, then stop.","tips":["Answer what was asked: 'It was missed — that's ours.'","The fix in the next breath: plate goes on now, take a look after.","The story of WHY it was missed adds guilt, not information."],"focus":["concision","clarity"]},
    {"id":"pressure-constr-early-02","level":"early","profession":"construction","title":"'Did you break this?'","scenario":"The homeowner holds up a cracked closet shelf you moved yesterday. You honestly don't know if you cracked it — it might have been cracked before. \"No\" is a gamble; a rambling maybe sounds like a dodge.","task":"Answer aloud: honest about what you know and don't, with what you'll do either way.","tips":["Say the true shape of it: 'I moved it yesterday and didn't notice a crack — but I can't swear it wasn't me.'","Then the offer: either way, I'll fix it before I leave.","Honest-uncertain plus action beats confident-wrong every time."],"focus":["clarity","audience"],"placeholder":"Honestly — I moved it yesterday and didn't see a crack, but I can't rule out that I did it. Either way, I'll have it fixed before I go today."},
    {"id":"pressure-constr-early-03","level":"early","profession":"construction","title":"Yes or no: done by Friday?","scenario":"The foreman cuts off your status update: \"Just tell me — done by Friday, yes or no?\" The true answer is 'yes, if the fixtures arrive Wednesday.' You need to give him the direct answer AND the condition without sounding like a dodge.","task":"Answer in two sentences: the yes/no first, the one condition second.","tips":["Lead with the closest true answer: 'Yes — with one dependency.'","Name the condition and its checkpoint: fixtures Wednesday; I'll flag Wednesday noon if not.","A conditioned yes delivered crisply IS a direct answer."],"focus":["clarity","precision"],"placeholder":"Yes — on one condition. Fixtures have to land Wednesday, and if they haven't by noon I'll tell you same day, not Friday."},
    {"id":"pressure-constr-early-04","level":"early","profession":"construction","title":"The code question you can't answer","scenario":"The homeowner asks whether her basement bedroom window meets egress code. You genuinely don't know the numbers off-hand. Bluffing a guess about safety code is the worst available option — but 'no idea' sounds like you don't know your trade.","task":"Say the 'I don't know' that builds trust: the gap, the path, the deadline.","tips":["Own the gap cleanly: 'I don't want to guess on egress numbers.'","Give the path: I'll measure it now and check the code table in the truck.","Time-box it: you'll have the answer in ten minutes, not 'sometime'."],"focus":["clarity","impact"],"placeholder":"I don't want to guess on egress — it's exact numbers. Give me ten minutes: I'll measure the opening and check it against the code table in my truck."},
    {"id":"pressure-constr-early-05","level":"early","profession":"construction","title":"Put on the spot about the sling","scenario":"Mid toolbox talk, the safety officer turns to you: \"What's the working load limit on the sling you used yesterday?\" Twenty people waiting. You used the right sling but the number isn't in your head. A confident wrong number is the career-limiting answer.","task":"Answer aloud without bluffing: what you did know, what you'll confirm.","tips":["Say what you verified in the moment: 'I checked the tag against the load before the lift — it was rated with margin.'","Admit the recall gap without collapsing: 'the exact number I'd have to read off the tag.'","Offer to close it: I'll pull the tag at break and post it."],"focus":["clarity","precision"]},
    {"id":"pressure-constr-early-06","level":"early","profession":"construction","title":"'Why did the price change?'","scenario":"The customer is holding the revised quote, visibly annoyed: \"You said twelve hundred. Now it's sixteen. Why?\" The answer is real — the wall opened up worse than the assessment could see — but under her tone you feel the urge to over-apologize or get stiff.","task":"Answer in 2-3 sentences: the direct reason, the specific change, and her options.","tips":["Answer 'why' first: 'Because the damage behind the wall is bigger than what was visible.'","Attach numbers to the difference: two more sheets, six more studs, half a day.","Give her a choice where one exists — that returns control."],"focus":["audience","clarity"],"placeholder":"Because the rot behind the wall goes further than anyone could see before we opened it. The extra $400 is six studs, two sheets, and the half day to do it — I can show you exactly where."},
    {"id":"pressure-constr-early-07","level":"early","profession":"construction","title":"The incident interview","scenario":"After the scaffold plank slipped, the safety officer sits you down: \"Walk me through what you were doing when it happened.\" You're rattled and your memory wants to editorialize — whose fault, what should've happened, how scared you were.","task":"Give the account aloud: facts in time order, no blame, no speculation.","tips":["Time-order the observable: where you stood, what you lifted, what moved, what you heard.","'I think' and 'probably' are fine labels for genuine uncertainty — use them honestly.","Leave fault-finding to the process; your job is a clean record."],"focus":["structure","precision"],"placeholder":"Around 9:40 I was on the second lift, handing block up to Marco. As I turned back, the plank under my left foot shifted about an inch —"},
    {"id":"pressure-constr-early-08","level":"early","profession":"construction","title":"'That can't be right'","scenario":"You report that the delivered beam is an inch too short. The foreman, without looking up: \"That can't be right, they cut from the same drawing.\" Getting louder loses; going quiet loses. What holds is the evidence, restated calmly.","task":"Say the response: your measurement, your method, and the invitation to verify.","tips":["Restate the fact with the method: 'I taped it three times — 11 foot 11 against a 12-foot callout.'","Invite the check without sarcasm: 'come throw a tape on it with me.'","Stay on the object, not the argument: the beam is what it is."],"focus":["impact","precision"],"placeholder":"I taped it three times against the drawing — beam's 11'11\", callout is 12'0\". Come throw a tape on it with me before we call the shop."},
    {"id":"pressure-constr-early-09","level":"early","profession":"construction","title":"Two questions at once","scenario":"The GC's PM catches you at the gate: \"Is your rough-in passing this week, and why was your crew parked in the loading zone this morning?\" Two unrelated questions, one impatient asker. Blended answers blur both.","task":"Answer aloud: take each question separately, in the order asked, one clean answer each.","tips":["Number your answers out loud: 'Two answers. Inspection: yes, booked Thursday. Parking: our mistake —'","Don't let the easy question hide the hard one.","Two clean sentences beat one tangled paragraph."],"focus":["structure","concision"],"placeholder":"Two answers. Inspection: yes — booked for Thursday, we're ready. Parking: that was us, my apologies — trucks move to the north lot starting tomorrow."},
    {"id":"pressure-constr-early-10","level":"early","profession":"construction","title":"The loaded question","scenario":"The site super, in front of others: \"Your crew always packs up twenty minutes early, don't they?\" It's loaded — 'always' is false, but Tuesday it was true. Swallowing the premise loses; angry denial loses; the factual middle wins.","task":"Answer aloud: correct the premise calmly, own the true part, done.","tips":["Reject the 'always' with facts, not heat: 'Tuesday we did — the other four days we were on till 4:30.'","Own the true instance and its reason if there was one.","Then stop. Defending past the facts reopens the question."],"focus":["impact","clarity"]},
    {"id":"pressure-constr-early-11","level":"early","profession":"construction","title":"Cost question on the spot","scenario":"During the walkthrough the homeowner points at the popcorn ceiling: \"While you're here — what would it cost to get rid of that?\" You're not the estimator, but 'no idea' wastes the moment and a fake number haunts the company.","task":"Answer aloud: honest bracket, the caveat, and the path to a real number.","tips":["Give a labeled range if you have one: 'ballpark, jobs like this run X to Y — don't hold me to it.'","Name what moves it: asbestos test, ceiling height, square footage.","Close with the path: I'll flag it to the office for a real quote by Friday."],"focus":["precision","audience"],"placeholder":"Ballpark only — rooms this size usually run $800 to $1,500, and it depends on an asbestos test first if the house is pre-90s. Want me to have the office price it properly this week?"},
    {"id":"pressure-constr-early-12","level":"early","profession":"construction","title":"'So whose fault is it?'","scenario":"The pipe got drilled — someone's screw found your water line, floor's wet, and the homeowner asks flat out: \"Whose fault is this?\" You suspect the cabinet installer but you didn't see it happen. Naming names on suspicion starts a war you can't finish.","task":"Answer aloud: what's known, what isn't, and where your energy is going.","tips":["Facts only: 'a screw hit the line behind the dishwasher — I don't know whose yet.'","Redirect from blame to sequence: water's off, fix is today, sorting responsibility is the office's job.","Never guess a culprit out loud to a customer."],"focus":["clarity","audience"],"placeholder":"A screw went through the line behind the dishwasher — I honestly don't know whose yet, and I won't guess. Water's off, I'm fixing it today, and the office will sort out responsibility."},
    {"id":"pressure-constr-early-13","level":"early","profession":"construction","title":"The half-known answer","scenario":"The foreman asks whether the old sewer line is clay or PVC. You scoped the first thirty feet — PVC — but past the property line you never saw. The full-confidence 'PVC' is half a bluff. The full 'don't know' throws away what you do know.","task":"Answer with the split: known part stated firmly, unknown part flagged, next step offered.","tips":["Give the known its full confidence: 'PVC for the first thirty feet — I scoped it.'","Flag the boundary of your knowledge exactly where it is.","Offer the close: camera the rest for certainty before we quote."],"focus":["precision","clarity"],"placeholder":"First thirty feet is PVC — I scoped that myself. Past the property line I've never seen; if the quote depends on it, we should camera the rest first."},
    {"id":"pressure-constr-early-14","level":"early","profession":"construction","title":"Invited to trash the other trade","scenario":"The homeowner, leaning in: \"Between us — the tile guy did a terrible job, right?\" There's one visibly lazy corner, and she wants you to say it. Piling on feels good for ten seconds and follows you around the industry for years.","task":"Say the response: honest about what you see, without the character verdict she's fishing for.","tips":["Describe, don't judge: 'that corner cut isn't what I'd want in my house — worth asking them to redo it.'","Route it usefully: flag it to the GC or the tile lead, in daylight.","Refusing the gossip while validating the concern is the whole skill."],"focus":["audience","impact"]},
    {"id":"pressure-constr-early-15","level":"early","profession":"construction","title":"Rapid fire at the walkthrough","scenario":"The super moves fast: \"When's this closing up? Where's the fire caulking? Who moved my ladder? Is the third floor done?\" Four questions in ten seconds, still walking. Chasing all four at his pace produces four half-answers.","task":"Respond aloud: slow the exchange down and answer one at a time, in your order.","tips":["Take the wheel politely: 'Let me take those in order.'","Answer the one with safety or schedule weight first.","One question, one complete sentence, then the next — your pace, not his."],"focus":["structure","concision"],"placeholder":"Let me take those in order. Fire caulking first — it's done on floors one and two, third floor happens tomorrow morning..."},
    {"id":"pressure-constr-early-16","level":"early","profession":"construction","title":"'Why should I trust your number?'","scenario":"You've told the foreman the opening is out of square by half an inch, which means the pre-hung door won't fit. He squints: \"You sure you're reading that right?\" Your competence is the thing under question, in public.","task":"Answer with method, not indignation: how you measured, and the offer to demonstrate.","tips":["Show the method: 'diagonals differ by half an inch — I measured corner to corner both ways, twice.'","Offer the live check: 'watch me run it again.'","Calm method under challenge is what senior sounds like."],"focus":["precision","impact"],"placeholder":"Fair to check — here's how I got it. Corner-to-corner diagonals are off by half an inch, measured twice each way. Watch me run it again right now if you want."},
    {"id":"pressure-constr-early-17","level":"early","profession":"construction","title":"Corrected in front of the crew","scenario":"At the huddle you said the inspection was Thursday. The foreman corrects you in front of everyone: \"It's Wednesday. Check your board.\" He's right. Ten faces turn to see what you do with it. Wilting and bristling both cost you.","task":"Say the recovery: brief acknowledgment, correction absorbed, forward motion.","tips":["Three beats: 'You're right — Wednesday. So the panel work needs to wrap Tuesday night.'","No excuse, no self-flagellation — the fastest recovery is using the correction immediately.","How you take a correction in public IS your reputation for taking corrections."],"focus":["impact","concision"]},
    {"id":"pressure-constr-early-18","level":"early","profession":"construction","title":"Suddenly on speaker","scenario":"You're mid-call with the property manager, talking freely about the job, when she says: \"By the way, I've got the building owner here with us on speaker.\" Whatever register you were in, the audience just changed — and the last thing you said was 'the previous work in there is a mess.'","task":"Say the next 2-3 sentences: recalibrate to the new audience without backpedaling into mush.","tips":["Don't retract facts — re-aim them: 'as I was saying, the existing wiring needs sorting before we build on it.'","Upgrade precision, drop the shop-talk looseness.","Acknowledge the owner and give the one thing they care about: cost and timeline shape."],"focus":["audience","clarity"],"placeholder":"Good timing — as I was saying, the existing wiring in the unit needs to be brought up to standard before we can build on it. For you, that means roughly..."},
    {"id":"pressure-constr-early-19","level":"early","profession":"construction","title":"'Can you do it cheaper?'","scenario":"You quoted the deck repair at $2,400 and the homeowner immediately asks, \"what can you do on the price?\" You're new at quoting and the urge is to cave $400 on the spot just to end the discomfort. The number was honest.","task":"Answer aloud: hold the quote, explain what it buys, and offer a scope-based option.","tips":["Hold with reasons, not apology: the number is materials plus two honest days.","Trade scope, not margin: 'it gets cheaper if we reuse the framing and just re-deck.'","'Let me think about what I can adjust' beats an instant cave — silence is allowed."],"focus":["audience","impact"],"placeholder":"The price is honest — it's the lumber plus two full days done right. If budget's the constraint, the real lever is scope: keep your framing and just re-deck, and it drops to about $1,700."},
    {"id":"pressure-constr-early-20","level":"early","profession":"construction","title":"Blamed for the last guy's work","scenario":"The inspector flags an unpermitted junction buried in the ceiling — work done years before your company ever touched the house. The homeowner rounds on you: \"You said everything you did was to code!\" It is. That isn't yours.","task":"Answer aloud: separate your scope from the finding without sounding like a dodge.","tips":["Draw the line with evidence, not defensiveness: 'everything we installed is documented — this junction predates us, and here's how you can tell.'","Show the tell: wire type, age, our labeled runs versus that one.","Then be useful about the found problem anyway — that's what keeps the client."],"focus":["clarity","precision"],"placeholder":"Everything we installed is to code and documented — I can walk you through it. That junction is older work, from before us: different wire era, none of our labeling. Here's what fixing it would take."},
    {"id":"pressure-constr-early-21","level":"early","profession":"construction","title":"When the honest answer is no","scenario":"It's 6 p.m., the furnace is apart, the part is wrong, and the family is standing in the kitchen: \"Will we have heat tonight?\" The answer is no. Every soft phrasing that hides the no just delays their planning by an hour.","task":"Deliver the no in the first sentence, then what you CAN do.","tips":["Say it: 'No — I can't get you heat tonight. The right part is a morning pickup.'","Immediately pivot to what's real: space heaters tonight, me at the supplier at 7, heat by 10.","A clean no with a plan is kinder than a mushy maybe."],"focus":["clarity","audience"],"placeholder":"No — I have to be straight with you, heat's not happening tonight. The right part is a 7am pickup. Here's what I can do right now: two space heaters from the truck, and I'm first in line at the supplier."},
    {"id":"pressure-constr-early-22","level":"early","profession":"construction","title":"The contract question that isn't yours","scenario":"Mid-job, the homeowner asks whether the contract covers repainting the patched wall. You genuinely don't know what her contract says — and guessing creates a promise the company has to eat. But 'ask the office' alone feels like a brush-off.","task":"Answer aloud: route it to the right person without dodging, and carry your part.","tips":["Be straight about the boundary: 'the contract's the office's call — I don't want to promise wrong.'","Carry it yourself: 'I'll text my PM right now and you'll have the answer today.'","Routing WITH ownership doesn't feel like a dodge; routing without it does."],"focus":["audience","clarity"],"placeholder":"That's written into your contract and I don't want to guess wrong on it. Here's what I'll do — I'm texting my project manager right now, and you'll have a straight answer before I leave today."},
    {"id":"pressure-constr-early-23","level":"early","profession":"construction","title":"Buying an hour, honestly","scenario":"The foreman calls: \"The GC needs to know RIGHT NOW if we can absorb the extra unit this month.\" You honestly can't answer without checking your material stock and the crew calendar. Pressure wants a yes; wisdom wants an hour.","task":"Say the response that buys the time without dodging: what you'll check, when you'll answer.","tips":["Name the checks, not just the delay: 'I need to count wire stock and look at the crew week.'","Commit to a time: 'you'll have a real answer by 1.'","A firm 'answer at 1' beats a soft yes that becomes Friday's crisis."],"focus":["clarity","precision"],"placeholder":"I can answer that properly by 1 today — I need to count our wire stock and check the crew calendar first. A guess right now helps nobody. 1 o'clock, you'll have a real yes or no."},
    {"id":"pressure-constr-early-24","level":"early","profession":"construction","title":"'How long have you been doing this?'","scenario":"You're about to cut into the ceiling when the homeowner asks, arms folded: \"How long have you been doing this, exactly?\" The true answer is eight months. Inflating it is a lie with a paper trail; mumbling it confirms her fear.","task":"Answer aloud: the true number, delivered with its real context, no flinch.","tips":["Say the number plainly, then the system around it: 'eight months, apprenticed under Dave, who checks my work daily.'","The confidence isn't in the number — it's in not being ashamed of it.","Offer the reassurance that's actually true: this exact job, I've done six times."],"focus":["audience","impact"],"placeholder":"Eight months in the trade — and this exact repair I've done six times, with my journeyman checking every one. He's a phone call away if anything surprises me. Fair question, by the way."},
    {"id":"pressure-constr-early-25","level":"early","profession":"construction","title":"'What happened?' after the near miss","scenario":"The dropped clamp missed the laborer's head by a foot, and now the crew is gathered around you, adrenaline up, everyone asking at once. What you say in the next thirty seconds either becomes the accurate story or the exaggerated one.","task":"Give the 30-second account aloud: what happened, what's true, what happens next.","tips":["Facts, plain and slow: what dropped, from where, where it landed, who was near.","Kill the speculation in the room by not adding your own.","End with the next step: work stops in that bay, it gets reported now, talk to the safety officer if you saw it."],"focus":["clarity","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-constr-early-01","level":"early","profession":"construction","title":"The prefab pitch","scenario":"You've noticed the crew builds every wall bracket from scratch, on ladders, in the weather. Batching them on the shop bench would be faster and cleaner — but 'we should prefab more' is an opinion, not a case. The foreman moves on cases.","task":"Write the pitch as before/after: the cost of now, the picture of after, the bridge between.","tips":["Before, with numbers: 20 minutes per bracket up a ladder, 30 brackets to go.","After, concrete: a bench jig, 6 minutes each, installed in two site days.","The bridge: give me one shop morning to build the jig and prove it."],"focus":["impact","structure"],"placeholder":"Right now every bracket is 20 minutes up a ladder — 30 left means two full days in the air. Give me one shop morning to build a jig: 6 minutes a bracket on the bench, and we install the lot in two days."},
    {"id":"narrative-constr-early-02","level":"early","profession":"construction","title":"Patch it or replace it","scenario":"The homeowner wants the corroded galvanized stack patched — cheapest option, works today. You've seen this movie: the patch holds a year, then fails inside a finished wall. She's not wrong to want cheap. She hasn't seen the ending you've seen.","task":"Make the case for replacement in 3-4 sentences: her stakes, made concrete, without fear-mongering.","tips":["Tell the honest future: the pipe next to the patch is the same age and the next leak picks its own spot.","Make the stakes hers and specific: drywall, flooring, the ceiling below — that's the real price of round two.","Then respect her call: patch is a real option, here's what each costs over five years."],"focus":["audience","impact"],"placeholder":"I can patch it today for $200 and it'll hold — for a while. But the whole run is the same age, and the next pinhole picks its own spot, usually inside the finished ceiling. Replacing the run now is $900; the same job after a ceiling failure is closer to $3,000."},
    {"id":"narrative-constr-early-03","level":"early","profession":"construction","title":"Beat the objection to the punch","scenario":"You want the crew to switch to the screw-in anchors, which cost forty cents more apiece. You already know what the foreman will say — 'they're pricier' — because he says it every time. A pitch that ignores the known objection loses to it.","task":"Write the pitch with the cost objection raised and answered before he can raise it.","tips":["Name it yourself: 'they're 40 cents more each — here's why that's the cheap option.'","Answer with the whole cost: failed pull-outs, callbacks, the redo hour at $95.","Owning the objection first takes its power away."],"focus":["structure","impact"],"placeholder":"Straight up: the screw-ins cost 40 cents more each. Here's the math anyway — we've redone eleven pull-out failures this quarter, an hour each. One callback costs more than 200 anchors."},
    {"id":"narrative-constr-early-04","level":"early","profession":"construction","title":"The story that sells the harness","scenario":"You're giving Friday's toolbox talk on fall protection, and the crew has heard the statistics until they're wallpaper. What they haven't heard is what you saw at your last company: the guy who clipped off for 'just a minute' to reach the far corner.","task":"Tell the two-minute story aloud so the lesson lands without you preaching it.","tips":["Tell it in scene, in time order: the corner, the unclip, the slip, the ledge — let it be specific.","Don't announce the moral; walk them to it and let the last line be theirs.","One story beats ten stats because the crew puts themselves in it."],"focus":["impact","audience"]},
    {"id":"narrative-constr-early-05","level":"early","profession":"construction","title":"Load the truck the night before","scenario":"Every morning the crew loses thirty minutes loading the truck while coffee goes cold and the site sits empty. Loading the night before would fix it — but it's a habit change, and 'we should really load at night' has been said and ignored twice already.","task":"Write the pitch to the crew that makes the change feel like their win, not a new chore.","tips":["Frame the payoff where they feel it: leave the yard at 7 sharp, first break comes earlier.","Make the ask tiny and testable: one week, loaded by 4:45, see if mornings improve.","Address the real objection — end-of-day fatigue — with the fifteen-minute cap."],"focus":["audience","impact"],"placeholder":"One-week experiment: we load before we leave — fifteen minutes, capped. In exchange, mornings we roll at 7 sharp and break comes at 9 instead of 9:40. If it doesn't feel better by Friday, we kill it."},
    {"id":"narrative-constr-early-06","level":"early","profession":"construction","title":"Reordering the trades","scenario":"The schedule has the painters in before the flooring — which means the flooring crew's rolling gear will scuff fresh baseboards and the painters will be back for touch-ups nobody budgeted. You're junior, but you've seen the sequence go wrong twice this year.","task":"Write the case to the foreman for flipping the sequence: the story of last time, then the proposal.","tips":["Lead with the last-time story, short: 'On Aspen Street this order cost the painters three touch-up days.'","Then the flip and its logic in two lines.","End with what it needs: one call to the paint lead, this week."],"focus":["structure","impact"],"placeholder":"Remember Aspen Street — painters before flooring, and their crew came back three days for scuffed baseboards. Same setup here. Flip it: floors Monday, painters Thursday, and nobody comes back twice. One call to the paint lead does it."},
    {"id":"narrative-constr-early-07","level":"early","profession":"construction","title":"Send me to the course","scenario":"There's a weekend gas-fitting certification course, $600, and you want the company to pay. \"It would be good for my development\" is what everyone says. The foreman signs off on things that solve HIS problems.","task":"Write the request framed around the company's gain, with the numbers.","tips":["Frame it as his story: every gas call now waits for Rick — I'd be the second ticket on the crew.","Numbers: we subbed out 9 gas calls last quarter at $300 each.","Make saying yes easy: course is the weekend of the 14th, I'll cover my own Saturday."],"focus":["impact","audience"],"placeholder":"We subbed out nine gas calls last quarter — about $2,700 — because Rick's the only ticket. The cert course on the 14th is $600, I'll give up my own weekend, and by spring the crew has two tickets instead of a bottleneck."},
    {"id":"narrative-constr-early-08","level":"early","profession":"construction","title":"The permit conversation","scenario":"The homeowner wants the basement bathroom done without a permit — 'my brother-in-law did his without one, it's fine.' You won't work unpermitted, but a flat refusal loses the job to someone worse. The persuasion is showing her the story she hasn't imagined: the sale.","task":"Make the case for the permit in 3-4 sentences built around her future, not the rules.","tips":["Skip 'it's the law' — start the story at her house sale: the buyer's inspector asks for the permit that doesn't exist.","Make the cost concrete: retroactive permits, walls opened for inspection, deals that die.","Then shrink the ask: the permit is $240 and two weeks — I handle the paperwork."],"focus":["audience","impact"],"placeholder":"Here's where the no-permit version ends up: you sell the house, the buyer's inspector sees a bathroom that's not on record, and now you're opening finished walls for a retroactive inspection mid-sale. The permit is $240 and two weeks, and I do all the paperwork."},
    {"id":"narrative-constr-early-09","level":"early","profession":"construction","title":"Before and after: the staging zone","scenario":"Material on this site gets dropped wherever the truck stops — the crew burns an hour a day hunting and hauling. You want a marked staging zone by trade. A whiteboard sketch and a picture of the difference will do what complaining hasn't.","task":"Write the 4-sentence pitch you'd give at the huddle: now, the cost, the after, the ask.","tips":["Paint 'now' without blame: everything lands at the gate, then walks the site twice.","Cost it: an hour a day across the crew is a lost man-week every month.","The after in one image: chalk lines by trade, material lands once, in reach."],"focus":["structure","clarity"],"placeholder":"Right now every delivery lands at the gate and gets carried twice — that's an hour a day, a man-week a month. Proposal: chalk out staging zones by trade, right side of the hoist. Material lands once, where it's used. Costs us one hour Saturday to line it."},
    {"id":"narrative-constr-early-10","level":"early","profession":"construction","title":"Fix the cause, not the symptom","scenario":"Third time this year: the same customer, the same drain, another auger call. It clears every time, and next quarter it clogs again. The real fix is the bellied pipe under the slab — a bigger, dearer job she's never wanted to hear about. This visit is your chance to tell the story right.","task":"Persuade her in 3-4 sentences: connect the repeat visits into one story with an ending.","tips":["Connect the dots she's living: three calls in a year isn't bad luck — it's one problem introducing itself three times.","Total the symptom-cost path: $180 a visit, forever, plus the flood risk.","Give the ending: fix the belly once, this stops being a subscription."],"focus":["impact","audience"],"placeholder":"This is my third visit for the same drain this year, and I need to be honest: these aren't three problems, they're one problem — a sag in the pipe under the slab — sending you the same bill every four months. You've paid $540 in clearing calls; the real fix is $2,200, once."},
    {"id":"narrative-constr-early-11","level":"early","profession":"construction","title":"Eleven tickets, one villain","scenario":"You pulled the quarter's callback tickets for the foreman like he asked. Eleven callbacks — and reading them, seven trace to the same budget shutoff valve the company started buying in January. A stack of tickets is data. Seven-out-of-eleven-is-one-valve is a story.","task":"Write the note that turns the ticket pile into one persuasive finding with an ask.","tips":["Lead with the story stat: 7 of 11 callbacks are one valve model.","Cost it: each callback is a truck roll plus an hour — the savings on that valve is a nickel against a $150 problem.","The ask: switch brands on this week's order."],"focus":["impact","precision"],"placeholder":"Went through the quarter's callbacks like you asked — 11 total, and 7 are the same part: the EconoFlow shutoff we switched to in January. Each callback is a $150 truck roll to save 60 cents a valve. Recommend we switch back on this week's order."},
    {"id":"narrative-constr-early-12","level":"early","profession":"construction","title":"The second ladder","scenario":"Your service van has one ladder, and twice this week you've had to decline attic-access jobs or drive back to the shop. A second ladder is $340. The office says no to 'it would be handy'; it says yes to jobs and dollars.","task":"Write the request built on the two lost jobs, with the payback math.","tips":["Open with the loss, dated: Tuesday and Thursday I turned work away or drove back — call it three billable hours.","Price the fix against one week's loss: the ladder pays for itself in under a month.","Ask for the specific: 28-foot extension, on next week's supply order."],"focus":["precision","impact"],"placeholder":"Twice this week — Tuesday and Thursday — I lost attic jobs because the van carries one ladder. That's about $400 in work plus the drive-backs. A second 28-footer is $340 and pays for itself the first week it saves a job."},
    {"id":"narrative-constr-early-13","level":"early","profession":"construction","title":"Make the substrate his problem","scenario":"The tile setter is about to lay over a subfloor you know flexes — you felt it walking the room. Not your trade, and he's prickly about being told his business. But when those tiles crack in six months, everyone gets dragged back. The persuasion has to run on HIS stakes.","task":"Say the 3-sentence pitch that makes checking the floor his idea.","tips":["Open with his stake, not your diagnosis: 'before you set — cracked tile callbacks land on you, right?'","Offer the observation as data, humbly: the floor moves near the window wall, worth a deflection check.","Give him the out that saves face: probably fine, but two minutes with a straightedge beats a callback."],"focus":["audience","impact"]},
    {"id":"narrative-constr-early-14","level":"early","profession":"construction","title":"The raise conversation","scenario":"You've been a first-year rate for eighteen months while doing second-year work — running your own small jobs, training the new helper. You want the bump. Walking in with 'I feel like I deserve more' hands the foreman nothing to say yes with.","task":"Write your case: the before/after of what you were hired as versus what you now do, with evidence.","tips":["Structure as then/now: hired to fetch and carry; now running the Mercer punch list solo and training Devon.","Evidence, not adjectives: three solo service calls a week, zero callbacks since March.","End with a clear, specific ask and a openness to a path: second-year rate, or tell me what's missing."],"focus":["structure","impact"],"placeholder":"When you hired me I was carrying material and watching. Eighteen months later I'm running solo service calls — three a week, no callbacks since March — and training Devon. I'm asking for second-year rate. If there's something between me and it, tell me and I'll close it."},
    {"id":"narrative-constr-early-15","level":"early","profession":"construction","title":"Protecting the cure time","scenario":"The GC wants to start framing on the slab Monday — four days after the pour, when the spec says seven. He's not reckless, he's squeezed; his lender walkthrough is Friday. Arguing spec numbers hasn't worked. What might: the story of what a cracked slab does to HIS Friday.","task":"Make the case in 3-4 sentences aimed at his actual pressure, with an alternative that helps him.","tips":["Acknowledge his squeeze first — persuasion starts where he is.","Play the tape forward on his terms: loaded slab at four days, hairline map cracks by the walkthrough, the lender's engineer asking questions.","Offer him a win: frame the garage side Monday — that pour is past cure — and the main slab Thursday."],"focus":["audience","impact"],"placeholder":"I know Friday's walkthrough is the real deadline, so here's my worry: load this slab Monday and by Friday your lender's engineer could be photographing map cracks. Counter-offer — the garage pour is past its cure, frame that Monday, and the main floor Thursday. You still show framing progress."},
    {"id":"narrative-constr-early-16","level":"early","profession":"construction","title":"What a leak costs later","scenario":"The homeowner wants to skip the shower waterproofing membrane — 'the old shower never had one and it was fine.' The $400 saving is visible today. The rot inside the wall in year six is invisible. Your job is to make the invisible one vivid without turning into a scare salesman.","task":"Write the 3-4 sentence case that makes the future cost as real as the present saving.","tips":["Make the failure specific and slow, not dramatic: tile grout isn't waterproof — a cup a week into the wall, silently, for years.","Show what discovery looks like: a soft baseboard in year five, and the fix starts with demolition.","Put the numbers side by side and let them argue: $400 now, $6,000 then."],"focus":["impact","audience"],"placeholder":"Grout isn't waterproof — without the membrane, the wall drinks a little every shower, silently, for years. You find out when a baseboard goes soft, and that repair starts with tearing out this tile. The membrane is $400 today; the year-six version of this conversation averages $6,000."},
    {"id":"narrative-constr-early-17","level":"early","profession":"construction","title":"'We've always done it this way'","scenario":"You've suggested pre-marking the layout with the laser instead of chalk lines and tape measures, and the pushback is instant: \"chalk's worked for thirty years.\" It has. Your case can't fight the pride; it has to enlist it.","task":"Say the response that honors the old way while making the case for the new one.","tips":["Agree first, honestly: chalk works — that's not the question. The question is the hour it takes versus fifteen minutes.","Frame the tool as serving their standard: same lines, same accuracy they taught you, quicker.","Propose the low-stakes trial: one room, side by side, loser buys coffee."],"focus":["audience","impact"]},
    {"id":"narrative-constr-early-18","level":"early","profession":"construction","title":"Selling the stretch","scenario":"The company rolled out morning stretch-and-flex and your crew treats it as a joke — five guys leaning on hammers while one guy touches his toes ironically. The foreman told YOU to make it stick. Preaching wellness to ironworkers is a losing script. Find the one that isn't.","task":"Write the 60-second talk that reframes the stretch in terms the crew already respects.","tips":["Ditch the wellness frame; use the athlete frame: nobody deadlifts cold, and we lift all day.","Use the local story: Benny's back went on a cold Monday lift — six weeks off, worst winter of his life.","Make it identity, not compliance: crews that last thirty years warm up. Ask Benny."],"focus":["audience","impact"],"placeholder":"Forget the corporate poster. You wouldn't max a deadlift straight out of the car, and the first block we hump this morning is exactly that. Benny lifted cold on a Monday — six weeks on his couch. Five minutes. That's the whole ask."},
    {"id":"narrative-constr-early-19","level":"early","profession":"construction","title":"One more day of dry","scenario":"The self-leveler needs another day before flooring, and the GC's scheduler is pushing hard: the flooring crew is booked tomorrow, moving them costs her a week of dominoes. Saying 'the spec says 48 hours' has already lost once today. Tell her what tomorrow actually looks like.","task":"Write the message that plays the tape forward for her schedule, then offers the least-bad path.","tips":["Her currency is the schedule, so cost it in schedule: floor laid on damp leveler bubbles in three weeks — that's a two-week tear-out, not a one-day slip.","Numbers make it real: moisture read 4.5 this morning; the flooring warranty wants 3.","Offer the salvage: crew starts tomorrow in the north unit — that side's dry — and this room Thursday."],"focus":["audience","structure"],"placeholder":"I know tomorrow's crew booking is the whole puzzle, so here's the honest math: lay floor on this leveler tomorrow (it read 4.5 this morning, warranty needs 3) and it bubbles in three weeks — a two-week tear-out. Alternative: start them in the north unit tomorrow, it's dry. This room Thursday."},
    {"id":"narrative-constr-early-20","level":"early","profession":"construction","title":"The middle faucet","scenario":"The homeowner is choosing between the $89 builder-grade faucet and the $340 designer one, paralyzed. You'd pick the $180 mid-range — you've replaced a dozen dead $89s and the $340 buys a logo, not longevity. 'Get the middle one' is a claim; your service-call history is a story.","task":"Make the recommendation in 3 sentences, letting your repair history do the persuading.","tips":["Recommend first, plainly: I'd put the $180 one in my own kitchen.","Then the evidence-story: the $89 model is a third of my service calls — same plastic cartridge every time.","Defuse the high end honestly: the $340 is a beautiful finish on the same $180 guts."],"focus":["audience","impact"],"placeholder":"I'd buy the $180 one for my own house. The $89 model keeps me employed — that plastic cartridge is a third of my service calls. And the $340? Gorgeous finish, same internals as the $180."},
    {"id":"narrative-constr-early-21","level":"early","profession":"construction","title":"Talking Devon into the trade","scenario":"Your cousin Devon is drifting after high school, half-interested when you talk about work. His mother thinks trades are what you do when college doesn't work out. You have one dinner-table shot at telling the story of your apprenticeship in a way that lands on both of them.","task":"Say the 60-second case aloud: your arc so far, told concretely, with the objection answered.","tips":["Tell it as your story, not a brochure: paid from day one, licensed at 22, zero debt, the house you can already see.","Meet the mother's objection head-on: this IS the version where school worked — four years, journeyman papers, and they paid me to earn them.","End with a small next step for Devon: one Saturday on site with me."],"focus":["audience","impact"]},
    {"id":"narrative-constr-early-22","level":"early","profession":"construction","title":"Decide while the window's open","scenario":"The homeowners have been 'thinking about' the furnace replacement for three weeks. You just learned the manufacturer's rebate — $1,200 — ends Friday, and install slots for the cold snap are nearly gone. Urgency is real here, but pushing too hard reads as a sales tactic.","task":"Write the nudge: honest urgency, dated facts, and a no-pressure exit.","tips":["Lead with the new fact, not the push: the rebate ends Friday — that wasn't true when we last spoke.","Stack the real dates: rebate Friday, two install slots before the cold snap, then it's January.","Leave the door genuinely open: if the answer's 'not this year', that's fine — I just didn't want you to miss it unknowingly."],"focus":["audience","clarity"],"placeholder":"One update that changes the math on the furnace: the $1,200 manufacturer rebate ends this Friday — it wasn't ending when we talked. We also have two install slots left before the cold snap. If the answer is 'not this year,' totally fine — I just didn't want the deadline to pass without you knowing."},
    {"id":"narrative-constr-early-23","level":"early","profession":"construction","title":"Getting the lift swapped today","scenario":"The rented scissor lift has a hydraulic drift the rental company calls 'within tolerance.' Your crew calls it unusable above the second level. The rental desk hears complaints all day; what they act on is contract language, safety words used precisely, and a customer who knows what he wants.","task":"Write the call script: the specific fault, the words that trigger action, the specific ask.","tips":["Describe the fault in their inspection language: platform drifts 4 inches under load at height — that's a lockout item, not a quirk.","Use the lever words honestly: unsafe to operate, tagged out, work stopped.","One ask with a time: swap unit on site by 1 p.m., or credit the day and we cross-rent."],"focus":["precision","impact"],"placeholder":"Unit 4471's platform drifts 4 inches under load at height — we've tagged it out as unsafe to operate and work in that zone is stopped. I need a swap on site by 1, or credit today and we cross-rent. Which one can you do?"},
    {"id":"narrative-constr-early-24","level":"early","profession":"construction","title":"The sequenced ask","scenario":"You need the drywallers to leave one chase open until Thursday — your last vent run got bumped by the window change. Their lead wants every wall closed by Wednesday, and 'can you just leave it open' sounds like disorder. A sequenced story sounds like a plan.","task":"Write the ask as a bridge: where things stand, the one change, the clean handoff with dates.","tips":["Situate first in one line: everything's closable except one chase, and here's why that changed.","Make the ask tiny and bounded: one bay, 4 feet wide, closed Thursday noon.","End with what he gets: my guy standing there Thursday 8 a.m., done by 11, mud by noon — in writing."],"focus":["structure","audience"],"placeholder":"You can close everything Wednesday except one 4-foot bay — the window change bumped my last vent run into it. I'll have a guy in that chase Thursday at 8, out by 11, and you're mudding it by noon. Every other wall is yours on schedule."},
    {"id":"narrative-constr-early-25","level":"early","profession":"construction","title":"Reporting isn't ratting","scenario":"The near-miss reporting box has been empty for two months — not because nothing's happened, but because the crew equates reporting with snitching. The foreman gave you the Friday talk slot to change that. The frame has to flip before the behavior will.","task":"Write the 90-second talk that reframes near-miss reporting as protecting the crew.","tips":["Open with the reframe: a near-miss report has no name in it — it's not about who, it's about what almost got one of US.","Use the concrete counter-story: the plank that slipped Tuesday — unreported — is still up there, waiting for the next guy.","Make the ask small and immediate: one card, thirty seconds, the thing you saw this week. I'll write the first one right now."],"focus":["audience","impact"],"placeholder":"A near-miss card has no names on it. It's not 'Marco messed up' — it's 'that plank almost took someone's head off, fix it before it does.' Tuesday's plank never got a card, and it's still up there. I'm writing the first one right now; the box needs thirty seconds from each of you."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-constr-early-01","level":"early","profession":"construction","title":"The week slips","scenario":"The window package is stuck at the border and the whole job slides a week. The homeowner has movers booked. Your draft message spends four sentences on the supplier saga before the slip appears. She needs the headline, not the journey.","task":"Write the message with the delay in the first sentence, then the new date and what you're doing about it.","tips":["First sentence: the job slips one week — new completion is the 22nd.","Cause in one line, no saga.","End with the action: I'll call at 4 to help re-plan the move-in."],"focus":["clarity","audience"],"placeholder":"I have bad news and a new date: the job slips one week, to the 22nd. The window shipment is stuck at the border — nothing we can pull forward. I'll call you at 4 to work through what this does to your movers."},
    {"id":"hard-constr-early-02","level":"early","profession":"construction","title":"You broke the vase","scenario":"Your drop cloth caught the pedestal and the customer's ceramic vase is in pieces. She's out for an hour. The temptations line up: glue it, hide it, blame the cat, or bury the confession in a wall of sorry. There's one right message and it's short.","task":"Write the note (or say the words for when she returns): what broke, that it was you, and what you'll do.","tips":["The fact and the ownership in one sentence: I knocked over the vase in the hall — it broke, and it was my fault.","One sentence of real apology — not five.","The making-right: the company's insurance covers it; here's the claim started."],"focus":["clarity","impact"],"placeholder":"I have to tell you something before anything else: I knocked the hallway vase over with my drop cloth and it broke. I'm very sorry. I've already told the office — our insurance covers it, and I'll walk you through the claim today."},
    {"id":"hard-constr-early-03","level":"early","profession":"construction","title":"No to the side job","scenario":"The homeowner pulls you aside: \"Forget the company — come back Saturday, cash, and do the garage subpanel yourself. You'd get all of it instead of whatever they pay you.\" It's flattering, illegal under your apprenticeship, and against company policy. The no has to be clean and warm.","task":"Say the decline aloud: direct no, brief reason, and the door kept open the right way.","tips":["No first, without a maybe hiding in it: I can't do that — work outside the company isn't something I do.","One reason is enough: my license conditions and my word to my employer.","Redirect to the legitimate path: I'd happily quote it through the office."],"focus":["clarity","audience"]},
    {"id":"hard-constr-early-04","level":"early","profession":"construction","title":"Your measurement, their problem","scenario":"The cabinets arrived and won't fit — because the wall dimension you called in six weeks ago was off by an inch and a half. Custom boxes, four-week lead time. The foreman needs to hear it from you, now, with the headline first and zero spin.","task":"Write the message: the error owned in sentence one, the impact, and your proposed path.","tips":["Own it at the top: the kitchen wall number was mine, and it was wrong by an inch and a half.","Impact without softening: the run doesn't fit; remake is four weeks.","Path: filler-strip option preserves the date — I've already asked the shop."],"focus":["clarity","structure"],"placeholder":"The cabinet problem is my error: I called the kitchen wall at 146\" and it's 144.5\". The run doesn't fit as built. Two paths — remake one box (4 weeks) or a filler strip at the fridge end (keeps our date). Shop says the filler is invisible; I'll show you."},
    {"id":"hard-constr-early-05","level":"early","profession":"construction","title":"Feedback to the helper","scenario":"The new helper's anchor work is genuinely unsafe — three of the five you checked turned by hand. He's eager, he's trying, and he'll be crushed by 'your work is bad.' But the shelving above a walkway can't care about feelings. The feedback has to be specific, kind, and non-negotiable.","task":"Say the feedback aloud: the specific problem, the standard, and the path — without sanding off the seriousness.","tips":["Specific beats general: three of these five anchors turn by hand — they'd let go under load.","Separate the work from the person: the torque habit is the issue, not you.","Rebuild together: watch me do two, then do two while I watch, every set gets the pull-test."],"focus":["clarity","audience"]},
    {"id":"hard-constr-early-06","level":"early","profession":"construction","title":"The quote missed something big","scenario":"Reviewing the plans at lunch, you realize the quote you helped assemble missed the entire second-floor radiant loop — about $4,000 of pipe and labor. The contract isn't signed yet, but the customer verbally agreed to the number. The office needs this before she signs, not after.","task":"Write the message to the office: the miss stated first, the size, and the two options.","tips":["Headline the miss: our quote for Fernwood is missing the upstairs radiant loop — roughly $4,000.","How it happened in one line, not a defense.","Options: correct it before signing (awkward now) or eat it (worse later) — recommend one."],"focus":["clarity","impact"],"placeholder":"Catch this before the Fernwood contract signs: our quote is missing the entire second-floor radiant loop — about $4,000. It fell between my takeoff sheet and the estimate. Recommend we call her today, own it, and reissue — awkward now beats a $4k hole later."},
    {"id":"hard-constr-early-07","level":"early","profession":"construction","title":"Turning down the job","scenario":"A neighbor from your street asks you to redo her aging knob-and-tube wiring 'on weekends, over a few months.' You like her, you could use the money, and it's beyond what you can legally or competently do solo. The no needs to protect her, not just excuse you.","task":"Write the decline: the no up front, the honest reason, and a real referral.","tips":["Decline in the first sentence — don't let hope build over a paragraph.","The reason is her safety, said plainly: this needs a licensed crew and permits, and weekend-me is neither.","Do the extra: two names of outfits who do this right, and an offer to look over their quotes."],"focus":["clarity","audience"],"placeholder":"I have to say no to this one, and I want to tell you why honestly: a knob-and-tube replacement needs a licensed crew, permits, and inspections — a weekend solo version shortchanges your safety. Two outfits I'd trust with my own house: Halden Electric and RW Power. I'll gladly sanity-check their quotes."},
    {"id":"hard-constr-early-08","level":"early","profession":"construction","title":"The mold behind the vanity","scenario":"Pulling the old vanity, you found black mold across four square feet of drywall. The homeowner is standing right there asking what's wrong. Mold panics people — and downplaying it to prevent panic is how companies get sued. Calm, factual, and unhedged is the lane.","task":"Say it aloud: the finding named plainly, the honest scale, and the immediate next steps.","tips":["Name it without euphemism: this is mold, about four square feet, likely from the old leak.","Scale it honestly both ways: needs proper handling; it is not a flee-the-house emergency.","Next steps concrete: I stop work in this room, we photograph it, and the office arranges testing."],"focus":["clarity","audience"],"placeholder":"I need to show you something — this is mold, about four square feet, from that old leak. It's not a tonight emergency, but it's not something I'm allowed to just cut out and forget. Work in this room pauses, and the office will have a remediation quote to you by tomorrow."},
    {"id":"hard-constr-early-09","level":"early","profession":"construction","title":"Over budget, number first","scenario":"The renovation is tracking $3,200 over the approved budget — the subfloor surprise plus the electrical upgrade the inspector required. The client meeting is in an hour and your foreman wants YOU to walk her through it. Burying the number under context reads as hiding it.","task":"Write your opening 3 sentences: the number first, then the two causes with their amounts.","tips":["Say the total in sentence one: we're $3,200 over the approved budget.","Split it cleanly: $1,900 subfloor rot, $1,300 code-required panel work.","Distinguish the unavoidable from the chosen — both of these were the former, say so with evidence ready."],"focus":["clarity","precision"],"placeholder":"I'll give you the number first: we're $3,200 over budget. Two causes — $1,900 of subfloor rot we found under the tub, and $1,300 of panel work the inspector required by code. Neither was optional; I've got photos and the inspector's notice to walk you through."},
    {"id":"hard-constr-early-10","level":"early","profession":"construction","title":"The cut list was wrong","scenario":"You framed all afternoon off Tomas's cut list before catching that every jack stud was cut to the wrong height — his transposition error, your crew's wasted lumber. He's a friend and he'll want to fix it quietly. The foreman still needs to know, from one of you, today.","task":"Say the conversation with Tomas: the error named, the deadline for telling the foreman, and how you'll back him.","tips":["Facts to Tomas first, no dance: the jacks are all at 81 — the list says 81, the plans say 82.5.","The hard part said kindly: this has to reach the foreman today, and better from you than found by him.","Back him up: it's a transposition anyone could make — I'll stand with you when you tell him."],"focus":["clarity","impact"]},
    {"id":"hard-constr-early-11","level":"early","profession":"construction","title":"The DIY wiring has to go","scenario":"The homeowner proudly shows you the basement circuit he ran himself off a YouTube series. It's wrong in three dangerous ways, and your panel upgrade can't legally connect to it. He's beaming. The message is: your work has to come out — delivered without making him feel like a fool in his own house.","task":"Say it aloud: the verdict clearly, the respect kept, the reasons concrete.","tips":["Verdict early and unhedged: I can't connect this — it has to come out and be redone.","Respect the effort while correcting the work: the routing's tidy, but the wire gauge and the missing ground are the deal-breakers.","Make the reasons physical, not personal: this gauge overheats at the load the breaker allows."],"focus":["audience","clarity"],"placeholder":"I'm going to be straight with you, because it's your family sleeping above this: I can't connect this circuit — it has to come out. Your routing is tidy work, but the wire's undersized for the breaker and there's no ground path, and both of those are fire-and-shock problems, not paperwork problems."},
    {"id":"hard-constr-early-12","level":"early","profession":"construction","title":"No to the free overtime","scenario":"It's 4:25 and the foreman says \"stick around and knock out the soffit — shouldn't take long\" for the third Friday straight, and the hours never hit your cheque. You want the apprenticeship reference; you're done working free. The no has to be steady and unheated.","task":"Say the decline aloud: the boundary, the reason, and the alternative offered.","tips":["The boundary without apology: I'm not staying off the clock — if it's on the clock, I'm happy to.","Keep history out of the heat: 'the last three Fridays weren't paid' is a fact, said once, flat.","Offer the workable path: log the OT properly or I'll hit it first thing Monday."],"focus":["impact","clarity"]},
    {"id":"hard-constr-early-13","level":"early","profession":"construction","title":"The warranty says no","scenario":"The customer is sure her sagging gate is a warranty fix. You've inspected it: the hinge posts are fine — her landscaper regraded the yard and the fence line moved. The claim is denied, she's already irritated, and you're the messenger standing in her yard.","task":"Deliver the denial: verdict first, the evidence shown, and a priced path forward.","tips":["Verdict without a fog of empathy-padding: this one isn't covered — the fence didn't fail, the ground under it moved.","Show, don't assert: the regrade line is visible against the post — walk her to it.","Never leave a denial bare: here's the fix and the price, and it's a small job."],"focus":["clarity","audience"],"placeholder":"I looked at everything, and I have to be honest: this isn't a warranty issue. Our posts haven't moved — the yard regrade last month changed the ground line, and you can see it right here against the post. The good news: rehanging the gate to the new grade is about $150, and I can do it Thursday."},
    {"id":"hard-constr-early-14","level":"early","profession":"construction","title":"Saturday is cancelled","scenario":"Half the crew rearranged their weekend for the Saturday shift — and now the client pushed the delivery, so Saturday's off. They find out either from a clean message tonight or a rumor tomorrow. Some of them were counting on the overtime pay.","task":"Write the crew text: the cancellation first, the reason honestly, and what happens to the hours.","tips":["Rip the band-aid in line one: Saturday is cancelled — client pushed the steel delivery.","Acknowledge the real cost: I know some of you planned around the OT.","Give what recovery exists: the hours move to next Saturday, first right of refusal to this list."],"focus":["clarity","audience"],"placeholder":"Bad news, straight up: Saturday's shift is cancelled — the client pushed the steel delivery to Tuesday. I know several of you rearranged plans and counted on those hours. The shift moves to next Saturday and everyone on this thread gets first claim on it."},
    {"id":"hard-constr-early-15","level":"early","profession":"construction","title":"Discontinued","scenario":"The tile the homeowners chose four months ago — the one the whole bathroom design hangs on — was discontinued last week. The supplier offered a 'close match' that isn't. You've got three real options and none of them is the tile they fell in love with.","task":"Write the message: the bad news plainly, then the three options with honest trade-offs.","tips":["No suspense: your tile was discontinued last week — I've checked every supplier in the region.","Kill the false hope early: the 'close match' isn't close enough for one wall; I'd only use it starting fresh.","Three real paths, honestly priced: re-select (free, weeks), the match everywhere (looks right, delays), or remnants hunt (gamble)."],"focus":["structure","audience"],"placeholder":"I wish I had better news on the tile: it's been discontinued, and I've checked six suppliers — no stock anywhere. The 'close match' the supplier offers isn't close enough to mix with what we have. Three honest options, and I'll bring samples of each tomorrow..."},
    {"id":"hard-constr-early-16","level":"early","profession":"construction","title":"Flagging a crewmate's shortcuts","scenario":"Ray has skipped the trench box twice this week — in a cut deep enough to bury him. You've said it to him directly; he laughed it off. Now it goes to the foreman, and the words matter: this is about the trench, not about torching Ray.","task":"Say it to the foreman: the specific unsafe acts, what you've already done, and what you're asking for.","tips":["Facts with dates, not character: Tuesday and today, in the 6-foot cut, no box.","Show you went to Ray first — that's what separates reporting from ratting.","Ask for the outcome, not the punishment: I want the box used, not Ray written up."],"focus":["clarity","impact"]},
    {"id":"hard-constr-early-17","level":"early","profession":"construction","title":"The bounced cheque","scenario":"The office flagged it: the Hendricks' deposit cheque bounced, and you're due at their house tomorrow morning to continue the job. They're good people, probably embarrassed, possibly unaware. The message has to collect without humiliating — and work can't continue until it clears.","task":"Write the message: the fact neutrally, the pause stated plainly, the easy fix offered.","tips":["Neutral mechanics, zero accusation: the deposit cheque came back from the bank — these things happen.","The consequence as policy, not threat: work pauses until the deposit lands; that's company standard, not personal.","Make fixing it frictionless: e-transfer or card by phone today, and tomorrow goes ahead as planned."],"focus":["audience","clarity"],"placeholder":"Quick one before tomorrow, and no stress — the deposit cheque came back from the bank, which happens to everyone. Company policy has me pause until it's sorted, but that's easy: e-transfer or card over the phone today, and I'm at your door at 8 as planned."},
    {"id":"hard-constr-early-18","level":"early","profession":"construction","title":"Tearing out your own work","scenario":"The tile you set Monday is wrong — you snapped your layout line off the unfinished wall edge instead of the room's center, and the pattern drifts visibly. Nobody's noticed yet. The right move is telling the foreman it comes out, before the grout, while it's a one-day fix.","task":"Write the message: your error, the fix window, and the cost — before anyone asks.","tips":["Confess at the cheap moment, not the caught moment: it's wrong, it's mine, and today it's still fixable.","Quantify the redo honestly: 40 square feet, one day, about $180 in tile.","The lesson line, once, forward-looking: layout gets snapped from the centerline, every room, from now on."],"focus":["clarity","impact"],"placeholder":"Before this gets grouted, I need to flag my own mistake: Monday's tile is off — I snapped layout from the wall edge, not center, and the drift shows. It has to come out. That's 40 sq ft, one day, about $180 in material, and it's on me to redo. Better today than after grout."},
    {"id":"hard-constr-early-19","level":"early","profession":"construction","title":"The water stays off tonight","scenario":"You promised the tenants water by 5. It's 4:30 and the replacement valve is cracked out of the box — the supply house is closed, and the honest answer is water at 9 tomorrow morning. Five families are about to make dinner. The building manager needs it now, and the message can't soften the timeline.","task":"Write the message to the building manager: the broken promise owned, the real timeline, and the interim plan.","tips":["Lead with the reversal: I told you 5 — I was wrong. Water's back at 9 tomorrow.","The reason is one line; the plan is the rest: defective part, supplier opens at 7, I'm first in line.","Bring the interim: I'm filling the hallway jugs now and posting notices on every door — approved wording attached."],"focus":["clarity","audience"],"placeholder":"I have to walk back my 5 o'clock promise: the replacement valve came out of the box cracked, the supplier's closed, and the honest answer is water at 9 tomorrow morning. Tonight: I'm filling water jugs for each unit and posting door notices in the next half hour — draft wording attached for your OK."},
    {"id":"hard-constr-early-20","level":"early","profession":"construction","title":"No permit, no me","scenario":"The landlord who feeds your company steady work wants the basement suite done without permits — 'like the last guys did.' Your foreman said the call is yours since you'd be running it. Losing this client is a real cost. Doing unpermitted life-safety work is a bigger one.","task":"Say the refusal: clean no, the reason that isn't a lecture, and the version of yes you can offer.","tips":["A no that doesn't wobble: I won't run this one unpermitted — that's firm.","Reason at his altitude: bedrooms and fire separations are the exact things permits exist for, and it's his liability when a tenant's involved.","The yes you CAN give: permitted version priced fair, my paperwork, two weeks — and I'll make the inspection painless."],"focus":["impact","audience"]},
    {"id":"hard-constr-early-21","level":"early","profession":"construction","title":"Pushing back up the ladder","scenario":"Three times this week the foreman changed the fixture layout after you'd already run the boxes — verbal instructions, each contradicting the last, and today's change means ripping out yesterday's work. He's not malicious, just scattered. Somebody junior has to say the unsayable, carefully.","task":"Say it: the pattern named respectfully, the cost in hours, and the one process fix you're asking for.","tips":["Name the pattern, not the person: the layout's changed three times this week, and each change re-does finished work.","The cost as a number he feels: that's nine crew-hours of rework since Monday.","Ask for the smallest fix: changes in the group text, written, before we rough them in — that's the whole request."],"focus":["clarity","impact"],"placeholder":"Can I flag something about the layout changes? Three this week, each after the boxes were run — that's about nine hours of redo since Monday. No issue with changes themselves — just asking that they land in the group text before we rough in, so we only build each wall once."},
    {"id":"hard-constr-early-22","level":"early","profession":"construction","title":"Failed inspection, GC edition","scenario":"The framing inspection failed on your company's blocking work — the GC's schedule now slips two days, and his Monday drywall crew has to be cancelled. He's going to be furious and he's going to hear it somewhere. Your foreman wants him to hear it from your company first, with the plan attached.","task":"Write the message to the GC: the failure and the slip up front, the cause owned, the recovery plan with dates.","tips":["Both headlines in sentence one: we failed framing on our blocking, and it costs the schedule two days.","Own the cause in one clause — no inspector-blaming.","Spend the rest on recovery: crew doubled tomorrow, re-inspection booked Thursday 8 a.m., drywall Friday — call me in ten if you want to go through it."],"focus":["clarity","structure"],"placeholder":"Calling this in before you hear it elsewhere: framing failed today on our blocking — our miss — and it costs two days; Monday drywall needs to move. Recovery: I've doubled the crew tomorrow, re-inspection is booked Thursday 8am, and drywall can start Friday. Free in ten minutes if you want to walk through it."},
    {"id":"hard-constr-early-23","level":"early","profession":"construction","title":"Giving notice","scenario":"A competitor offered you a journeyman-track position with the papers your current company keeps postponing. Your foreman taught you most of what you know, and Thursday you have to tell him you're leaving. Gratitude and departure have to live in the same short conversation.","task":"Say it: the decision first and unhedged, the reason honest, the gratitude real, the transition offered.","tips":["Decision first so hope doesn't build: I've accepted another position — my last day is the 30th.","The reason without indictment: they're signing my journeyman paperwork now; that's the whole difference.","Offer a real transition: two weeks, my job notes written up, and I'll walk Devon through my open items."],"focus":["clarity","audience"]},
    {"id":"hard-constr-early-24","level":"early","profession":"construction","title":"The dog got out","scenario":"The homeowners are away; you're the only trade in the house — and someone left the gate ajar during the lumber delivery. Their dog is gone. Neighbors are helping you search, but the owners deserve the call NOW, not after you've either found him or run out of daylight.","task":"Say the phone call: the fact immediately, what's already happening, and how you'll keep them updated.","tips":["No wind-up — they'll hear it in your voice anyway: Rusty got out during our delivery about twenty minutes ago.","Actions already moving: three of us searching, the neighbor's checking the ravine path, his photo's on the community page.","Set the update rhythm: I'll call every 30 minutes whether there's news or not."],"focus":["clarity","impact"]},
    {"id":"hard-constr-early-25","level":"early","profession":"construction","title":"The final bill is higher","scenario":"The final invoice is $840 over the estimate — every dollar legitimate, every change approved verbally at the time, but scattered across six small mid-job conversations she's likely forgotten. Sent bare, the invoice reads as padding. The cover message has to reconnect each dollar to its moment.","task":"Write the cover message: the difference stated first, then each addition tied to its approval moment.","tips":["Name the gap before she finds it: the final is $840 over the estimate — here's exactly where.","Each line: the item, the cost, and the conversation: 'the second hose bib — $180 — you asked for it during the May 12 walkthrough.'","Close with the standing offer: happy to go line by line on a call, and nothing bills that we didn't discuss."],"focus":["precision","audience"],"placeholder":"Before you open the invoice: the final is $840 over the estimate, and I want to show you each piece rather than have you hunt. The second hose bib ($180) from our May 12 walkthrough; the upgraded fan you chose over the quoted one ($95 difference, May 20 text)..."}
  ],
  "putting-it-together": [
    {"id":"together-constr-early-01","level":"early","profession":"construction","title":"The daily report, full stack","scenario":"End of day, one text box in the company app, and everything you've practiced in one deliverable: a delay to flag, progress to report, a materials need, and tomorrow's plan. The office reads it in ten seconds tonight and the foreman builds tomorrow off it at 6 a.m.","task":"Write the complete daily report: headline first, labeled sections, every line earning its place.","tips":["The one thing that changes tomorrow goes in line one — the delay, not the progress.","Labels do the structure: PROGRESS / ISSUE / NEED / TOMORROW.","Read it back as the foreman: can he build the morning plan from this alone?"],"focus":["structure","concision"],"placeholder":"ISSUE FIRST: tub surround tile delayed to Thurs — bathroom sequence flips (details below). PROGRESS: unit 2 rough-in done, tested..."},
    {"id":"together-constr-early-02","level":"early","profession":"construction","title":"One burst pipe, three audiences","scenario":"A supply line let go overnight in the reno house: basement's wet, today's schedule is dead, and three people need to hear it in the next ten minutes — the foreman, the homeowner, and the drywall crew booked for noon. Same facts, three completely different messages.","task":"Write all three messages, each shaped for its reader: foreman (decisions), homeowner (her house), drywall lead (his day).","tips":["Foreman gets triage and decisions: what failed, what's soaked, insurance-or-not, what you need.","Homeowner gets her house and her plan: what happened, what's protected, when normal returns.","Drywall lead gets one thing: don't come at noon — new time by 3."],"focus":["audience","structure"],"placeholder":"TO FOREMAN: Burst supply line at Fernwood overnight — basement carpet soaked, drywall got the bottom foot on two walls. Water's off, extraction fan running. Need: insurance call or we eat it?..."},
    {"id":"together-constr-early-03","level":"early","profession":"construction","title":"The incident report that holds up","scenario":"A pallet strap snapped during unloading and a bundle of conduit caught Marcus's shoulder — he's okay, checked out, back Monday. Now the full incident report: facts in order, precision on every detail, structure the safety office can process, and zero speculation dressed as fact.","task":"Write the complete report: time-ordered narrative, then contributing factors, then recommendations — each section doing only its own job.","tips":["Narrative section: only what happened, timestamped, in sequence — measurements and positions, not blame.","Factors labeled as analysis: strap condition, load position, where people stood.","Recommendations each tied to a factor: strap inspection at receiving, exclusion zone during unloading."],"focus":["structure","precision"],"placeholder":"INCIDENT: 07:52, east laydown. Sequence: forklift set the conduit pallet down; as J.T. cut the second strap, the first strap — already frayed — let go..."},
    {"id":"together-constr-early-04","level":"early","profession":"construction","title":"The change-order conversation, end to end","scenario":"The homeowner wants the kitchen island moved 18 inches — which drags plumbing, electrical, and flooring with it. You're on site, she's asking now, and the full conversation is yours: explain the ripple, give the honest number, set the timeline, get the decision moving. Every skill, one doorway chat.","task":"Script the complete conversation: the answer to 'can you?', the translated scope, the price and time, and the clear next step.","tips":["Open with the honest headline: yes, and it's bigger than it looks — three trades follow that island.","Translate each ripple to her world: the drain moves under the floor, so the floor opens.","Land on one concrete next step: written change order tonight, price locked, you decide by Friday and the schedule holds."],"focus":["audience","structure"],"placeholder":"Short answer: yes, we can move it — and I want to be straight that 18 inches of island is really three trades of work. The drain and supply move under the slab, power follows, and that section of floor opens and recloses..."},
    {"id":"together-constr-early-05","level":"early","profession":"construction","title":"Voicemail plus follow-up text","scenario":"The inspector didn't show for the 1 p.m. rough-in slot and his voicemail box is where messages go to die. You need the combo: a voicemail that's tight enough to act on, and a follow-up text that survives being read at a red light — both carrying the same ask without contradicting each other.","task":"Script both: the 20-second voicemail and the 2-line text, same facts, each built for its channel.","tips":["Voicemail: name, site, the miss, the ask, number — slow on the number, nothing else slow.","Text: the same ask compressed to two lines with the permit number he'll need.","One ask across both: tomorrow's first slot — don't introduce options the channels can disagree on."],"focus":["concision","audience"],"placeholder":"VM: Hi, this is Sam from Ridgeline at 44 Fernwood, permit 22481. We were booked 1pm today for rough-in — no show. Requesting your first slot tomorrow. 555-0142. TEXT: Ridgeline @ 44 Fernwood, permit 22481 —"},
    {"id":"together-constr-early-06","level":"early","profession":"construction","title":"The materials request with no callbacks","scenario":"Friday's pour needs a supply order placed today, and the office bats about .500 on getting orders right from tech texts. This one has no room for error: specific products, exact quantities, a hard deadline, and the one acceptable substitution — all in a message that generates zero clarifying calls.","task":"Write the complete order request: structured, specified, deadlined, substitution rules included.","tips":["Structure by line item, numbered, quantity first: '1) 40 bags Type S mortar'.","Pre-answer the callback: acceptable sub for each item, or 'no sub — call me'.","Deadline with consequence attached: on site by Thursday 3 or Friday's pour slides a week."],"focus":["precision","structure"],"placeholder":"Order for Fernwood, need ON SITE by Thurs 3pm (Friday pour depends on it): 1) 40 bags Type S mortar — sub OK: any Type S. 2) 6 lengths #4 rebar 20' — no sub, call me first..."},
    {"id":"together-constr-early-07","level":"early","profession":"construction","title":"The walkthrough email that runs eleven jobs","scenario":"You walked the second floor with the GC's PM this morning and promised her a summary. She runs eleven projects; yours gets ninety seconds of her attention. The email needs the verdict up top, grouped findings, owners and dates on everything — a document she can forward without editing.","task":"Write the complete walkthrough summary email: headline verdict, grouped items, each with an owner and a date.","tips":["Subject line does half the work: '2nd floor walkthrough: ready except 3 items, all closed by Thurs'.","Group by owner, not by room — she forwards each group to one person.","Every item: what, where, who, when. No item without all four."],"focus":["structure","audience"],"placeholder":"Subject: 2nd floor walk — ready except 3 items, all closable by Thurs. Hi Dana — verdict first: second floor is drywall-ready everywhere except the items below..."},
    {"id":"together-constr-early-08","level":"early","profession":"construction","title":"The vacation handoff package","scenario":"You're out for a week and Priya inherits your three active jobs cold. Everything unwritten walks out the door with you Friday: the seized valve trick at the Marsh house, the homeowner who needs a heads-up call before any visit, where the special-order parts are hiding. One document has to be you, for a week.","task":"Write the complete handoff: per-job status, next actions, landmines, and contacts — organized so Priya finds Tuesday's answer on Tuesday.","tips":["One block per job, same skeleton each: STATUS / NEXT / WATCH OUT / CONTACT.","Landmines get verbs: 'cut the union, don't wrench it — it's seized and the pipe behind flexes.'","Write for her worst moment: 7 a.m., customer on the phone, you unreachable."],"focus":["structure","clarity"],"placeholder":"MARSH HOUSE — STATUS: valve swap half done, water back on via bypass. NEXT: new valve arrives Tues to office, install Wed. WATCH OUT: the union above the tank is seized — cut it, don't wrench it..."},
    {"id":"together-constr-early-09","level":"early","profession":"construction","title":"The mini-excavator pitch, complete","scenario":"Six more footings to dig by hand this week, and a mini-excavator rents for $280 a day. You've done the math and it wins — but the foreman has heard a hundred 'rent the machine' pitches. This one gets SCQA structure, real numbers, the objection pre-answered, and a one-word-answer ask.","task":"Write the full pitch: situation, complication, your answer with math, the objection handled, the clean ask.","tips":["Situation and complication in two lines: six footings left; hand-digging runs 4 crew-days at $95/hour each.","The math visible: $280/day for 2 days versus roughly $3,000 of labor — show the subtraction.","Pre-empt his objection (operator?): I'm ticketed on it from the Hensley job. Ask: rent Thursday–Friday, yes or no?"],"focus":["structure","impact"],"placeholder":"Six footings left, all hand-dig in that clay — honest estimate is 4 crew-days, call it $3,000 of labor. A mini-ex is $280/day and does it in 2, and I'm ticketed on it from Hensley. $560 against $3,000. Can I book it Thursday?"},
    {"id":"together-constr-early-10","level":"early","profession":"construction","title":"Apology, fix, prevention","scenario":"Your crew's compressor ran at 6:40 a.m. — twenty minutes before the bylaw allows — and the neighbor who complained is the same neighbor considering your company for her own reno. The message back is a complete performance: real apology, immediate fix, believable prevention, no groveling, no excuses.","task":"Write the complete response: the apology that names the offense, the fix already made, and the prevention with a mechanism.","tips":["Name what you did specifically — vague sorry reads as form-letter: we ran the compressor at 6:40, twenty minutes early, and that's on us.","Fix in past tense, already done: it stays off until 7:00 sharp, starting today.","Prevention needs a mechanism, not a promise: it's on a timer plug now — it physically can't start early."],"focus":["audience","impact"],"placeholder":"You're right, and I want to own it specifically: our compressor was running at 6:40 this morning, twenty minutes before bylaw hours. That's our mistake, not a gray area. As of today it's on a timer plug that physically can't start it before 7:00..."},
    {"id":"together-constr-early-11","level":"early","profession":"construction","title":"Four questions, one reply","scenario":"The homeowner's evening email has four questions tangled in three paragraphs: when does tile start, can the vanity move six inches, what's the extra outlet cost, and why was the water off Tuesday. Answering in a mirror-tangle wastes her time; answering only two invites two more emails.","task":"Write the reply that answers all four, each visibly, in the order that serves her.","tips":["Break her paragraphs into your numbered answers — make each question findable.","Order by what she needs first, not the order asked: the vanity decision blocks tile, so it leads.","One question needs a decision from her — end the email on exactly that."],"focus":["structure","audience"],"placeholder":"Great questions — all four answered here. 1) VANITY: yes it can move 6\", but I need your yes/no by Thursday because... 2) TILE: starts Monday..."},
    {"id":"together-constr-early-12","level":"early","profession":"construction","title":"Rewrite your worst text","scenario":"Scroll your actual sent messages from this week and find the worst one — the buried lede, the missing quantity, the vague 'soon', the ramble before the ask. Every drill in this course is a lens; now point them all at your own writing.","task":"Pick one real message you sent and rewrite it: point first, structured, cut to the bone, precise, aimed at its reader.","tips":["Run the checklist: first sentence carries the point? Numbers where numbers belong? Anything the reader doesn't need?","Compare word counts — the rewrite should usually be half.","Notice the pattern in YOUR misses; that pattern is next week's habit to break."],"focus":["clarity","concision"]},
    {"id":"together-constr-early-13","level":"early","profession":"construction","title":"The first solo estimate, spoken","scenario":"The office is letting you present your own estimate for the first time: a fence replacement, $3,850, and the homeowners are standing in their yard waiting. The full stack in two minutes, spoken: the number early, the scope structured, the terms precise, the confidence calibrated — and then the hardest part, stopping.","task":"Deliver the estimate aloud: price up front, scope in three clean parts, what's excluded, timeline, and the close.","tips":["Number in the first two sentences — making them wait for it reads as hiding it.","Scope in buckets they can picture: tear-out and haul-away, posts and framing, boards and gate.","Name the exclusion before they find it: sprinkler lines near the posts are theirs to flag. Then the close: questions, then I'll email this in writing tonight."],"focus":["structure","audience"],"placeholder":"The full job comes to $3,850, and here's exactly what that buys. Three parts: first, we tear out and haul away the old fence..."},
    {"id":"together-constr-early-14","level":"early","profession":"construction","title":"Escalating after two dead ends","scenario":"You've asked the drywall lead twice — politely, specifically — to stop screwing into your marked plumbing wall without checking, and today there's a third screw through a pipe. Escalating to the super now is right, but the message has to carry the history without reading as a tantrum.","task":"Write the escalation: the incident, the two prior asks with dates, the cost, and the specific intervention you need.","tips":["Open with today's fact, not your frustration: third screw through the marked wall, third leak repair.","The paper trail in two flat lines: asked June 3 and June 10, both times directly, both times agreed.","Ask for a mechanism, not sympathy: a no-fasten zone on the layout drawings and one toolbox mention."],"focus":["structure","impact"],"placeholder":"Escalating this because two direct asks haven't fixed it: today we pulled a third screw out of the marked plumbing wall in unit 2 — third leak repair on our tab. I raised it with the drywall lead June 3 and June 10..."},
    {"id":"together-constr-early-15","level":"early","profession":"construction","title":"Running the huddle","scenario":"The foreman's stuck at the permit office and texted: \"run the 7am huddle.\" Six guys, ninety seconds, and everything you've practiced in one live delivery — the day's headline, three assignments, one safety flag, one open question routed to the right person. No notes app. Out loud.","task":"Deliver the huddle brief aloud: signposted open, assignments by name, the safety item unmissable, and a clean end.","tips":["Open with the map: 'Four things: the day's goal, assignments, one safety flag, one question.'","Assignments are name-first: 'Marco — units 1 and 2 rough-in.' Names make orders land.","The safety flag gets its own beat and a pause: open trench, east side, barriers up before anything else."],"focus":["structure","impact"]},
    {"id":"together-constr-early-16","level":"early","profession":"construction","title":"The job-complete wrap message","scenario":"The Alvarez bathroom is done — final walkthrough passed, area cleaned, warranty starts today. The last message on a job sets what the customer remembers and what the review says. It needs the completion confirmed, the practical details (warranty, invoice, care), and a close that earns the referral without begging for it.","task":"Write the complete wrap-up message: done and verified, the three practical facts, and the professional close.","tips":["Open with the completion as a small ceremony: your bathroom is done, tested, and walked through as of today.","The practicals in one scannable block: invoice timing, warranty length and what it covers, the one care instruction that matters (no caulk-line scrubbing for 48 hours).","The close is confident, not needy: it was a good project — if it ever needs anything, one text to this number."],"focus":["audience","structure"],"placeholder":"The bathroom is officially done — final walkthrough complete, everything tested, site cleaned out as of this afternoon. Three practical things: the invoice comes tomorrow by email; your two-year warranty on all our work starts today..."},
    {"id":"together-constr-early-17","level":"early","profession":"construction","title":"Calling off the pour","scenario":"It's 5:50 a.m., sleeting sideways, and the forecast confirms it: today's pour is dead. You're first on site, so the cancellation cascade is yours — the batch plant needs it by 6 to release the slot without a fee, the crew's already driving, the GC plans his week off it. Three messages, right order, no wasted minutes.","task":"Write all three messages in the order you'd send them, each complete for its reader.","tips":["Sequence by cost of delay: plant first (fee cutoff at 6), crew second (they're burning gas), GC third (he needs the replan, not the sleet report).","Plant gets order number and the reschedule ask in one breath.","Crew message answers their only question: come in or stay home — don't make six guys text back 'so...?'"],"focus":["structure","audience"],"placeholder":"TO PLANT (5:52am): Cancelling order 8834, Fernwood pour, weather — releasing the 9am slot before the 6am cutoff. Requesting first available Thursday. Confirm? TO CREW: ..."},
    {"id":"together-constr-early-18","level":"early","profession":"construction","title":"Untangling the group thread","scenario":"The job's group text is forty messages of chaos: two versions of the tile start date, an unanswered question about the vanity, a materials list half-confirmed, and the homeowner asking things nobody answered. Someone needs to post the one message that resets the thread to facts. You're someone.","task":"Write the reset message: current facts stated, open questions named with owners, dead information explicitly killed.","tips":["Label it as the reset: 'Summary as of Wednesday 4pm — this supersedes everything above.'","Facts get flat statements with dates; the two tile dates die here: tile starts Monday the 14th, not the 7th.","Open items get names attached: 'Vanity height — waiting on Lisa's pick by Friday.'"],"focus":["structure","clarity"],"placeholder":"Resetting this thread — summary as of Wed 4pm, supersedes everything above. CONFIRMED: tile starts Mon the 14th (not the 7th — that date's dead). Vanity stays at 36\"..."},
    {"id":"together-constr-early-19","level":"early","profession":"construction","title":"Your toolbox talk, built from scratch","scenario":"The foreman gave you Friday's five-minute talk and — for the first time — no company handout. Topic's yours. The complete build: pick the one idea worth five minutes, structure it as three points, open with the story that earns attention, and land an ask small enough to actually happen.","task":"Write the full talk: story open, one governing idea, three supporting points signposted, one specific ask.","tips":["Open in a scene, not a policy: Tuesday, the extension cord across stairwell B, and the guy carrying drywall who never saw it.","Say the map out loud: 'One idea, three parts.' The crew relaxes when they know the shape.","The ask passes the Monday test: will anyone do it Monday? 'Be safer' fails; 'cords go overhead on hooks, starting today' passes."],"focus":["structure","impact"]},
    {"id":"together-constr-early-20","level":"early","profession":"construction","title":"The case for yourself, in writing","scenario":"The company posted an internal opening: crew lead for the new service division. You want it at eighteen months in — ambitious but not crazy, IF the written application makes the case with evidence instead of enthusiasm. One page, read by an owner who's met you twice.","task":"Write the application: your claim up front, three evidence blocks, the gap owned honestly, the close.","tips":["Open with the claim and its shape: I'm asking to be considered — early, and here's the case anyway.","Evidence blocks, each one fact: zero callbacks since March; ran the Mercer job solo through punch list; trained both new helpers.","Own the obvious objection before he raises it: eighteen months is early — so here's the 90-day check-in I'd propose to de-risk it."],"focus":["structure","impact"],"placeholder":"I'm putting my name in for the service crew lead. Eighteen months in, that's an early ask — here's why I'm making it anyway, in three facts. First: zero callbacks on my work since March..."},
    {"id":"together-constr-early-21","level":"early","profession":"construction","title":"The stop-work cascade","scenario":"Cutting into the old ceiling, you exposed pipe wrap that looks exactly like the asbestos insulation from your training photos. Work stops NOW — and then the messages, in the right order: your crew in the room, the foreman, and the note for the homeowner arriving home at 5. Calm, precise, no dramatics, no minimizing.","task":"Script the cascade: the verbal stop to the crew, the foreman message with specifics, and the homeowner note — each at its right altitude.","tips":["Crew gets the immediate and physical: down tools, out of the room, door closed, nobody sweeps — dust is the hazard.","Foreman gets the decision package: location, what it looks like, photo attached, area sealed, testing company or not — your ask.","Homeowner gets calm precision: suspected, not confirmed; sealed; tested within 48 hours; the room stays closed meanwhile."],"focus":["clarity","audience"],"placeholder":"TO CREW (verbal): Tools down, everybody out of the den — that pipe wrap could be asbestos. Door closed, nobody sweeps or touches anything. TO FOREMAN: Found suspect pipe wrap in the den ceiling at Fernwood..."},
    {"id":"together-constr-early-22","level":"early","profession":"construction","title":"Your month, in ninety seconds","scenario":"New company policy: every apprentice gives a monthly ninety-second review to the foreman and the owner. Yours is Friday. A month of work — two jobs finished, one licensing course passed, one expensive mistake owned and fixed — compressed into a spoken brief that shows the judgment, not just the list.","task":"Deliver the review aloud: headline the month, three highlights with evidence, the mistake included deliberately, the ask at the end.","tips":["Headline like a report, not a diary: 'Strong month with one expensive lesson — here's both.'","The mistake belongs in the middle, owned in one line with its fix — hiding it costs more than saying it.","End with a forward ask: more solo service calls, the gas course, whatever you actually want — reviews are when asking works."],"focus":["structure","concision"]},
    {"id":"together-constr-early-23","level":"early","profession":"construction","title":"Answering the complaint email","scenario":"The homeowner's complaint email landed at 9 p.m., cc'ing the owner: the site was left 'a disaster', someone smoked near the house, and the gate was open again. One item is fully true, one is half-true, one wasn't your crew. The reply is due by morning and every sentence will be reread twice.","task":"Write the complete reply: each item addressed by name, the true owned, the half-true clarified without lawyering, the false corrected gently, and the fix for all three.","tips":["Take the items in her order, each visibly answered — skipping one confirms it.","Own the true one first and fully: the site was left rough Thursday — no excuse, here's the new end-of-day sweep.","Correct the false one with facts, not indignation: no one on our crew smokes; the drywall crew is separate — I've flagged it to their lead. Zero sarcasm anywhere."],"focus":["audience","structure"],"placeholder":"Thank you for the direct email — all three points deserve straight answers. The site Thursday: you're right, and I won't dress it up. We left it rough and that's below our standard. Starting today, last fifteen minutes of every day is cleanup, no exceptions..."},
    {"id":"together-constr-early-24","level":"early","profession":"construction","title":"Punch list closed, with proof","scenario":"All fourteen punch items are done, and the final holdback payment releases when the GC accepts your completion report. 'All done, see attached pics' has bounced back before. This report needs every item closed with its evidence — organized so acceptance takes him three minutes and zero site visits.","task":"Write the completion report: headline, items grouped as originally listed, each with what-was-done and its photo reference.","tips":["Mirror his numbering exactly — he'll check your list against his, so make them the same list.","Each item: his words, then yours: '#7 hallway drywall gouge — patched, sanded, painted (photo 7a/7b before-after).'","End with the specific ask and its consequence: confirm acceptance by Friday so the holdback releases on this month's cycle."],"focus":["structure","precision"],"placeholder":"Punch list completion — all 14 items closed, evidence attached, numbered to match your list of June 2. #1 NE bedroom closet door rub: planed and rehung, closes clean (photo 1a)..."},
    {"id":"together-constr-early-25","level":"early","profession":"construction","title":"The day everything went wrong","scenario":"The capstone: delivery came four hours late and wrong, the pressure test failed on a joint you'll fix tomorrow, the homeowner cornered you about the schedule and you handled it — barely — and the crew lost half a day. Now the end-of-day message to the foreman. Every module you've practiced, one message, real stakes.","task":"Write the complete end-of-day message: triaged headline, structured sections, precise facts, honest ownership, and tomorrow's plan — under 150 words.","tips":["Triage the headline: of the four fires, the failed test drives tomorrow — it leads.","One labeled line per issue: FACT, then STATUS, then what you need — resist the paragraph.","Ownership where it's yours, precision where it's not: the joint is yours to refit; the delivery error has a claim number already."],"focus":["structure","impact"],"placeholder":"Rough day, compressed: TEST: pressure test failed at one joint — my refit, first thing tomorrow, re-test by 10. DELIVERY: 4 hrs late and wrong (2x8 not 2x10) — refused, claim #4471 filed, redelivery Thurs 7am..."}
  ],
};
